HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/88/BIG_IMG_3666-copy_158107342588.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/88/BIG_IMG_3666-copy_158107342588.jpg","https://static.peakview.bg/img/data2/121/hoteli/88/BIG_a_DSC10623_158107342588.jpg","https://static.peakview.bg/img/data2/121/hoteli/88/BIG_aIMG_89262_158107342588.jpg","https://static.peakview.bg/img/data2/121/hoteli/88/BIG_Ba%C5%9Fl%C4%B1ks%C4%B1z-51_158107342588.jpg","https://static.peakview.bg/img/data2/121/hoteli/88/BIG_IMG_2690-copy_158107342588.jpg","https://static.peakview.bg/img/data2/121/hoteli/88/BIG_IMG_3525-copy_158107342588.jpg","https://static.peakview.bg/img/data2/121/hoteli/88/BIG_IMG_89282_158107342588.jpg","https://static.peakview.bg/img/data2/121/hoteli/88/BIG_r1_158107342588.jpg","https://static.peakview.bg/img/data2/121/hoteli/88/BIG_r2_158107342588.jpg","https://static.peakview.bg/img/data2/121/hoteli/88/BIG_r3_158107342588.jpg","https://static.peakview.bg/img/data2/121/hoteli/88/BIG_r4_158107342588.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е разположен на 118 км. от летище Анталия, на 50 м. от плажа, на 1 км. от центъра на гр.Алания.</p><p><strong>В стаите:</strong>Климатик, сателитна телевизия, телефон, баня с душ, сешоар, мини бар (платено), сейф (платено), балкон. Почистване на стаите - всеки ден, смяна на бельото и кърпите - 3 пъти в седмицата.</p><p><strong>На територията на хотела: </strong>Хотелът разполага общо с 188 стаи, от които 135 стандартни стаи и 53 фамилни. </p><p>Удобства:</p><p>Оновен ресторант, а-ла-карт ресторант (срещу доплащане, с предварителна резервация), 2 бара, 2 открити басейна, магазини, СПА център.</p><p>Безплатни Услуги:</p><p>турска баня, Wi-Fi, плажен волейбол</p><p>Платени Услуги:</p><p>сауна, масаж, телефон, факс, водни спортове, лекар, билярд, център за красота, тенис на маса, дартс, билярд </p><p>Плаж:</p><p>Градски, пясъчен. Шезлонги, чадъри и матраци - платено. Чадъри и матраци на басейна - безплатно.</p><p><strong>Хранене:</strong>All Inclusive </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_200415524_17652819581372.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_200415524_17652819581372.jpg","https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_200411058_17652819581372.jpg","https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_200415471_17652819581372.jpg","https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_200534730_17652819581372.jpg","https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_200535826_17652819581372.jpg","https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_198397191_17652819581372.jpg","https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_198396787_17652819581372.jpg","https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_198397034_17652819581372.jpg","https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_200331419_17652819581372.jpg","https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_200331424_17652819581372.jpg","https://static.peakview.bg/img/data2/121/hoteli/1372/BIG_198397537_17652819581372.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотел Campus Hill се намира в Алания, на 1,5 километра от плажа Kestel и на 2,1 километра от плажа Портакал.</p><p><strong>В стаите:</strong>Хотелът се състои от основна 11-етажна сграда: 90 стандартни стаи (макс. 2+1 човека, 21 м2); 40 апартамента (1 спалня, 1 хол, макс. 5 човека, 45 м2). В стаите санитарен възел, климатик, мини-бар и сейф (срещу заплащане), кабелна телевизия, телефон и тераса с изглед към градината и морето.</p><p><strong>На територията на хотела: </strong>Концепция на хранене</p><p>Хотелът разполага с бар, кафене и ресторант.</p><p>Забавления и спорт</p><p>джакузи парна баня дискотека (срещу допълнително заплащане) музика на живо (1 път седмично) волейбол на плажа тенис на маса моторизирани водни спортове (срещу допълнително заплащане) сауна турска баня (хамам) фитнес анимация дартс билярд (срещу заплащане ) масаж (срещу допълнително заплащане) уроци по гмуркане (срещу допълнително заплащане) велосипеди под наем външен басейн с 3 водни пързалки Вътрешен басейн SPA-център</p><p><strong>Хранене:</strong>Концепция на хранене</p><p>Хотелът разполага с бар, кафене и ресторант. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG_158099942692.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG_158099942692.jpg","https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG2_158099942792.jpg","https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG3_158099942892.jpg","https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG4_158099942892.jpg","https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG5_158099942992.jpg","https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG6_158099943092.jpg","https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG7_158099943092.jpg","https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG8_158099943192.jpg","https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG9_158099943292.jpg","https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG10_158099943292.jpg","https://static.peakview.bg/img/data2/121/hoteli/92/BIG_IMG11_158099943392.jpg"],stars:3,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотел от градски тип, разположен в центъра на гр. Алания, на 120 км. от международното летище на Анталия и на около 100 метра от известния плаж на Клеопатра.</p><p>Официално открит през 2013 г., последно реновиран през 2016 г.</p><p><strong>В стаите:</strong>Хотелът се състои от две шестетажни сгради, разполагащи с общо 58 стаи.</p><p>Всички стаи са оборудвани с климатик, сателитна телевизия, телефон с директно избиране, баня с душ, сешоар, минибар, сейф, безжичен интернет, детски креват и балкон.</p><p>Безплатно ползване на безжичен интернет в стаите.</p><p>Ежедневно почистване на стаите. Смяна на спалното бельо – 3 пъти в седмицата. Смяна на кърпите – по желание на гостите.</p><p><strong>На територията на хотела: </strong>В хотела:</p><p>Ресторант, два бара, открит басейн, детски басейн, дартс и билярд, тенис на маса, безжичен интернет в лоби и в стаите.</p><p>Платени услуги:</p><p>Ползване на сейф, пералня, чадъри и шезлонги на плажа, водни спортове.</p><p>Плаж:</p><p>Гостите на хотела могат да наемат чадъри и шезлонги на градския плаж на Алания срещу допълнително заплащане.</p><p>Безплатно ползване на чадъри и шезлонги само при басейна.</p><p><strong>Хранене:</strong>Хотелът функционира на база All Inclusive, която включва закуска, обяд и вечеря на блок маса и неограничена консумация на местни алкохолни и безалкохолни напитки в интервала от 10:00 ч. до 23:00 ч. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_19710071_17679497611402.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_19710071_17679497611402.jpg","https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_19714938_17679497611402.jpg","https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_19716262_17679497611402.jpg","https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_19717710_17679497611402.jpg","https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_19718527_17679497611402.jpg","https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_70354951_17679497611402.jpg","https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_70355219_17679497611402.jpg","https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_19718117_17679497611402.jpg","https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_19718019_17679497611402.jpg","https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_547280819_17679497611402.jpg","https://static.peakview.bg/img/data2/121/hoteli/1402/BIG_10909050_17679497611402.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Разположение</p><p>Хотелът е разположен на 120 км от летището в град Анталия, на 6 км от град Алания, на 3 км от селището Конаклъ, на 600 м през пътя от плажа, до който се стига чрез подземен преход. Хотелът е построен през 1996 г. с обща площ 6200 м2. Последно реновиран през 2007 г.</p><p><strong>В стаите:</strong>В стаите</p><p>баня с вана (само в 8 family room) баня с душ сешоар индивидуален климатик телевизор телефон мини-бар (празен, платено) сейф (в стаите, срещу заплащане) под – ламинат балкон (освен в 1 от стаите за инвалиди), почистване на стаите - ежедневно смяна на спалното бельо – 3 пъти седмично.</p><p><strong>На територията на хотела: </strong>На територията на хотела</p><p>основен ресторант 4 бара 2 открити басейна 2 водни пързалки лекар на повикване SPA-център фризьорски салон магазини пералня конферентна зала. Плаж: Собствен, пясъчен. Бар на плажа: безплатно. Чадъри, шезлонги – безплатно; матраци – срещу заплащане. Плажни хавлии: няма. При басейна: чадъри, шезлонги, матраци – безплатно.</p><p><strong>Хранене:</strong>All inclusive-закуска,обяд и вечеря,допълнителни хранения, алкохолни и безалкохолни напитки местно производство без лимит. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_501775839_17658945001388.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_501775839_17658945001388.jpg","https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_501774855_17658945001388.jpg","https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_501774845_17658945001388.jpg","https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_501774801_17658945001388.jpg","https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_485713924_17658945001388.jpg","https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_502269237_17658945001388.jpg","https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_502269099_17658945001388.jpg","https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_502269267_17658945001388.jpg","https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_502269037_17658945001388.jpg","https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_502269030_17658945001388.jpg","https://static.peakview.bg/img/data2/121/hoteli/1388/BIG_501775310_17658945001388.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Разположение:</p><p>Намира се на 110 км. от летище Анталия, на 120 км. от центъра на Анталия, на 10 км. от центъра на Алания, в селището Конаклъ, на 200 м. от брега на морето. Построен през 2013 г., реновиран 2018 г., с обща площ 35.000 м².</p><p><strong>В стаите:</strong>В стаите</p><p>Хотелът разполага с 485 стаи, разположени в основна сграда и анекс сграда. Всички стаи са оборудвани с климатик, телевизор, телефон, баня с душ/вана, сешоар, минибар, сейф, балкон. Почистване на стаите – всеки ден, смяна на кърпите и спалното бельо – 2 пъти в седмицата.</p><p><strong>На територията на хотела: </strong>На територията на хотела</p><p>Основен ресторант, 1 а-ла-карт ресторанта (средиземноморски - платен), 4 бара, 3 открити басейна, 2 водни пързалки, дискотека, амфитеатър, СПА център, магазини, 2 конферентни зали, паркинг, Wi-Fi (платен).</p><p>За децата: детски басейн, детска площадка, мини клуб (4-11г.).</p><p>Безплатни услуги: Сауна, турска баня, фитнес, дартс, аеробика, мини футбол, плажен волейбол, тенис на маса, дартс, водна гимнастика, плажен волейбол.</p><p>Платени услуги: масаж, сауна, фризьор, химическо чистене, лекар, водни спортове, интернет.</p><p><strong>Хранене:</strong>All Inclusive – закуска, обяд и вечеря на шведска маса, междинни хранения, местни алкохолни и безалкохолни напитки – без лимит. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/987/BIG_1079-aa9f9-1_1708511322987.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/987/BIG_1079-aa9f9-1_1708511322987.jpg","https://static.peakview.bg/img/data2/121/hoteli/987/BIG_1079-57c23-3_1708511322987.jpg","https://static.peakview.bg/img/data2/121/hoteli/987/BIG_1063-d4f39-4_1708511322987.jpg","https://static.peakview.bg/img/data2/121/hoteli/987/BIG_1079-708b2-5_1708511322987.jpg","https://static.peakview.bg/img/data2/121/hoteli/987/BIG_1079-808cd-6_1708511322987.jpg","https://static.peakview.bg/img/data2/121/hoteli/987/BIG_1079-f52c5-7_1708511322987.jpg","https://static.peakview.bg/img/data2/121/hoteli/987/BIG_1079-7df4a-8_1708511322987.jpg","https://static.peakview.bg/img/data2/121/hoteli/987/BIG_1079-62257-9_1708511322987.jpg","https://static.peakview.bg/img/data2/121/hoteli/987/BIG_1079-7f85b-10_1708511322987.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Намира се на 135 км. от летище Анталия, на 140 км. от центъра на Анталия, в центъра на Алания, в непосредствена близост до плажа. Обща площ на хотела 13.100 м2.</p><p><strong>В стаите:</strong>Хотелът разполага със следните типове стаи: Standard Room Side Sea View (25 m2), Standard Room Land View (25 m2), Eco Family Room (40m2), Family Room (40 m2).</p><p>Всички стаи са оборудвани с електронна система за заключване, климатик, мини бар (зарежда се с безалкохолни напитки веднъж при пристигане), сет за кафе и чай , LCD телевизор, сейф, телефон, баня с душ, сешоар, балкон.</p><p><strong>На територията на хотела: </strong>Основен ресторант, 3 бара, 1 открит басейн, 3 водни пързалки, СПА център, Wi–Fi.</p><p>За децата: Детски открит басейн, мини клуб (4-12), детска дискотека.</p><p>Безплатни услуги: Сауна, турска баня, фитнес, дневна анимация, тенис на маса, вечерни шоута, жива музика (в определени дни), сейф.</p><p>Платени услуги: Козметични услуги, масажи, магазин, коли под наем, бебешка количка, телефон, пране и гладене.</p><p>Собствен, пясъчно-чакълест с дължина 150 м. (до пажа се стига през подлез). Чадъри и шезлонги на плажа и при басейна – безплатно. Плажни кърпи – безплатно.</p><p><strong>Хранене:</strong>Ultra All Inclusive – закуска, обяд и вечеря на шведска маса, междинни хранения, алкохолни и безалкохолни напитки – без лимит (съгласно концепцията на хотела). </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/974/BIG_image004_1730472315974.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/974/BIG_image004_1730472315974.jpg","https://static.peakview.bg/img/data2/121/hoteli/974/BIG_F1-POOL%20BAR%20OVER%20VIEW_1746599208974.jpg","https://static.peakview.bg/img/data2/121/hoteli/974/BIG_pool-beach_654f96077ac9f_1702542015974.jpg","https://static.peakview.bg/img/data2/121/hoteli/974/BIG_pool-beach_654f96077c123_1702542015974.jpg","https://static.peakview.bg/img/data2/121/hoteli/974/BIG_D4-RASTAURANT%20POOLVIEW_1746599208974.jpg","https://static.peakview.bg/img/data2/121/hoteli/974/BIG_D3-RESTAURANT%20OVERVIEW_1746599208974.jpg","https://static.peakview.bg/img/data2/121/hoteli/974/BIG_D6-RESTAURANT%20TERRACE%20OVERVIEW_1746599208974.jpg","https://static.peakview.bg/img/data2/121/hoteli/974/BIG_C13-FAMILY%20ROOM_1746599208974.jpg","https://static.peakview.bg/img/data2/121/hoteli/974/BIG_C14-FAMILY%20ROOM_1746599208974.jpg","https://static.peakview.bg/img/data2/121/hoteli/974/BIG_C15-FAMILY%20ROOM_1746599208974.jpg","https://static.peakview.bg/img/data2/121/hoteli/974/BIG_C17-ROOM%20CORRIDORS_1746599208974.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира на брега на морето, на разстояние - 15 км. от Алания и на 109 км. от международното летище на Анталия. Разположен на площ 30 000 кв.м. построен през 1999г</p><p><strong>В стаите:</strong>Хотелът разполага с 253 стаи в 9 отделни сгради. Всяка една стая е оборудвана с климатик, сателитна телевизия, телефон, баня с душ/вана, сешоар, мини бар, сейф, балкон или тераса. </p><p>Последно реновирани стаи 2012г. и бани 2018 г.</p><p><strong>На територията на хотела: </strong>Хотелът разполага с основен ресторант, 3 бара, плувен басейн, детски басейн, водни пързалки, СПА център, сауна, турска баня, фитнес, тенис на маса, тенис на корт, водни спортове, анимация, конферентна зала. Безплатни услуги: турска баня, сауна, баскетбол, плажен волейбол, тенис корт/без осветлението/, тенис на маса, детски клуб, дискотека, караоке. Платени услуги: вносни алкохолни напитки, румсървиз, магазини, оборудване на тенис, химическо чистене,интернет. За децата: мини клуб/4-12г./, детски басейн, анимация за деца, детска площадка.</p><p><strong>Хранене:</strong>Ultra All İnclusive закуска, обяд и вечеря на шведска маса, междинни хранения, местни и някои вносни алкохолни и безалкохолни напитки - без лимит, съгласно концепцията на хотела. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/791/BIG_pool-beach-5_1677242460791.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/791/BIG_pool-beach-5_1677242460791.jpg","https://static.peakview.bg/img/data2/121/hoteli/791/BIG_general-3_1677242460791.jpg","https://static.peakview.bg/img/data2/121/hoteli/791/BIG_general-4_1677242460791.jpg","https://static.peakview.bg/img/data2/121/hoteli/791/BIG_family-1_1677242460791.jpg","https://static.peakview.bg/img/data2/121/hoteli/791/BIG_general-5_1677242460791.jpg","https://static.peakview.bg/img/data2/121/hoteli/791/BIG_general-11_1677242460791.jpg","https://static.peakview.bg/img/data2/121/hoteli/791/BIG_general-12_1677242460791.jpg","https://static.peakview.bg/img/data2/121/hoteli/791/BIG_general-14_1677242460791.jpg","https://static.peakview.bg/img/data2/121/hoteli/791/BIG_general-20_1677242460791.jpg","https://static.peakview.bg/img/data2/121/hoteli/791/BIG_general-23_1677242460791.jpg","https://static.peakview.bg/img/data2/121/hoteli/791/BIG_general-25_1677242460791.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира в района на Конаклъ, на 800 метра от центъра на градчето, на 12 километра от град Алания и на 110 километра от град Анталия.</p><p>Официално е открит през 1998 г. на обща територия от 9000 кв. м., последно е реновиран през 2019 г.</p><p>Хотелът е отдалечен на 500 метра от собствен плаж. До плажа е осигурен пешеходен достъп посредством подземен тунел, като се предлага и беплатен шатъл бус. Чадъри, шезлонги на плажа и при басейна – безплатно. Плажни кърпи – срещу заплащане .</p><p><strong>В стаите:</strong>Хотелът разполага с общо 225 стаи, от които 220 стандартни стаи, 23 фамилни стаи и 2 стаи за инвалиди.</p><p>Всички стаи са оборудвани с балкон, климатик, LCD телевизор със сателитен приемник, телефон с директно избиране, баня с душ, сешоар, минибар (безплатно презареждан с вода), сейф (платен), безжичен интернет (безплатен), ламинирано подово покритие.</p><p><strong>На територията на хотела: </strong>Основен ресторант, лоби бар, бар при басейна, витамин бар, бар на плажа (12:00-16:00 ч.), основен открит басейн, релакс басейн, детски басейн, басейн на плажа, басейн с водни пързалки, SPA център със закрит басейн, турска баня и сауна, фитнес център, софт анимация, спортни и развлекателни дейности, търговски център, безплатен безжичен интернет на територията на цецлия хотел, безплатен паркинг за гости на хотела.</p><p>За децата хотелът предлага открит детски басейн, детска игрална площадка, мини клуб за деца от 4 до 12 навършени години, детска анимация.</p><p><strong>Хранене:</strong>Хотелът фунционира на база All Inclusive, включваща закуска, обяд и вечеря на блок маса в основния ресторант, допълнителни закуски и неограничена консумация на местни алкохолни и безалкохолни напитки в интервала от 10:00 ч. до 24:00 ч. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_49921311_17654571381382.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_49921311_17654571381382.jpg","https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_187476452_17654571381382.jpg","https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_408983562_17654571381382.jpg","https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_725879472_17654571381382.jpg","https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_143305965_17654571381382.jpg","https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_725875767_17654571381382.jpg","https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_510683228_17654571381382.jpg","https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_725879294_17654571381382.jpg","https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_725858541_17654571381382.jpg","https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_725864500_17654571381382.jpg","https://static.peakview.bg/img/data2/121/hoteli/1382/BIG_725865865_17654571381382.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Замъкът на Алания се намира на 6 км от хотел Oba Star. Персоналът на денонощната рецепция може да съдейства за кола под наем. На място има безплатен обществен паркинг.</p><p><strong>В стаите:</strong>Стаите в хотел Oba Star са с балкони с панорамна гледка и са декорирани в неутрални цветове. Обзаведени са с модерни дървени мебели и са оборудвани със сателитна телевизия и минибар.</p><p><strong>На територията на хотела: </strong>Този 4-звезден хотел се намира на 2 км от центъра на Алания и на по-малко от 100 метра от собствения си пясъчен плаж. Разполага с открит басейн с тераса с шезлонги и предлага климатизирани стаи.</p><p><strong>Хранене:</strong>Ресторантът на място предлага международна кухня и турски вечери на шведска маса. В плажния бар на Oba Star гостите могат да се насладят на освежаващи напитки. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_IMG_15641361241987_1644492640827.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_IMG_15641361241987_1644492640827.jpg","https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_42689814_616834755379800_7492997328966516736_n_16155636611987_1644492640827.jpg","https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_58443353_724157061314235_1967928399842246656_o_16155636611987_1644492640827.jpg","https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_82414479_916459652083974_7875720692187004928_n_16155636611987_1644492640827.jpg","https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_83067208_916459902083949_139610879778881536_n_16155636611987_1644492640827.jpg","https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_land-of-paradise-beach%20%282%29_16155636611987_1644492640827.jpg","https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_land-of-paradise-beach-standart-oda-797464c6-ee2f-47eb-a2ae-bbcf7fd65ef4_16155636611987_1644492640827.jpg","https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_82515027_916460122083927_4864381956885839872_n_16155636611987_1644492640827.jpg","https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_42631813_615919778804631_8205696093166501888_o_16155636611987_1644492640827.jpg","https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_82581706_921808688215737_4614006842660487168_o_16155636611987_1644492640827.jpg","https://static.peakview.bg/img/data2/121/hoteli/827/BIG_BIG_82588567_921808731549066_389580686530445312_o_16155636611987_1644492640827.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира на 98 км от летището в Анталия, на 22 км от гр. Алания и на 3 км от селището Турклер, на брега на морето. Хотелът е построен през 1990 година, обща площ 9 000 м2. Последно реновиран през 2018 година.</p><p><strong>В стаите:</strong>Хотелът разполага с едно 6-етажна сграда, и четири 4-5 етажни корпуса - общо 250 стаи.</p><p>Стаите разполага с индивидуален климатик, телевизор, телефон, баня с душ, сешоар, балкон, мини-бар (в деня на пристигане е заредена вода безплатно), сейф (платен), Wi Fi (платен), под - теракота или ламинат.</p><p>Почистване на стаите - ежедневно, смяна на бельо - 2 пъти седмично.</p><p><strong>На територията на хотела: </strong>Основен ресторант, 1 Ресторант a la carte - рибен с предварително записване, 1 посещение при престой от 5 дена - безплатно; 3 бара, 2 открити басейна, закрит басейн, Аквапарк, 2 конферентни зали, магазини, лекар, фризьор.</p><p>Безплатни услуги: турска баня, сауна, тенис на маса, дартс, плажен волейбол, анимация, водна гимнастика, аеробика.</p><p>Платени услуги: масажи, водни спортове, Wi-Fi.</p><p>За децата: детски клуб (за деца от 4 до 12 години), детска площадка, детски басейн.</p><p>Плаж:</p><p>Собствен, пясъчен плаж. Чадъри, шезлонти, матраци - безплатно, плажни хавлии - безплатно, при смяна се плаща. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG_1678114382819.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG_1678114382819.jpg","https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG2_1678114383819.jpg","https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG3_1678114384819.jpg","https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG4_1678114385819.jpg","https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG5_1678114386819.jpg","https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG6_1678114387819.jpg","https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG7_1678114388819.jpg","https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG8_1678114389819.jpg","https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG9_1678114390819.jpg","https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG10_1678114391819.jpg","https://static.peakview.bg/img/data2/121/hoteli/819/BIG_IMG11_1678114392819.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>KAILA CITY HOTEL</strong></p><p>Kaila City Hotel се намира на първа линия в Алания, на 1,8 километра от плажа Кестел. Предлага различни удобства, като фитнес център, бар и частен плаж. Разполага с денонощна рецепция, ресторант, воден парк и открит басейн. Има турска баня, вечерни развлечения и рум-сървиз.</p><p>Стаите за гости в хотела разполагат с телевизор със сателитни канали. Стаите в Kaila City Hotel разполагат с климатик и гардероб.</p><p>Сутрин се сервира закуска на шведска маса или халал закуска.</p><p>Уелнес зоната в Kaila City Hotel се състои от СПА център и сауна.</p><p>Площад &bdquo;Ататюрк&ldquo; в Алания е на 4,1 км от хотела, а аквапарк &bdquo;Алания&ldquo; е на 5 км. Най-близкото летище е Газипаша, на 35 км от Kaila City Hotel. Хотелът предлага платен летищен трансфер.</p><p>Концепция на хотела</p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG_1641468707820.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG_1641468707820.jpg","https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG2_1641468711820.jpg","https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG3_1641468713820.jpg","https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG4_1641468715820.jpg","https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG5_1641468717820.jpg","https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG6_1641468719820.jpg","https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG7_1641468720820.jpg","https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG8_1641468723820.jpg","https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG9_1641468726820.jpg","https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG10_1641468728820.jpg","https://static.peakview.bg/img/data2/121/hoteli/820/BIG_IMG11_1641468729820.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>KAILA KRIZANTEM</strong></p><p>Ол-инклузив хотел Krizantem се намира в квартал Оба и предлага частен пясъчен плаж на Средиземно море. Хотелът предлага 3 сезонни открити басейна, детска площадка и водна пързалка. Има традиционна турска баня, сауна и фитнес център.</p><p>Хотелът предлага стаи с климатик, сателитна телевизия, минибар и сейф. Всички стаи разполагат с балкон, а някои стаи имат изглед към морето или градината.</p><p>Ресторантът на хотел Krizantem предлага традиционни турски ястия. В баровете до басейна се предлагат разнообразни напитки, включително коктейли.</p><p>На плажа се предлагат разнообразни спортни занимания, като джет ски, дърпане с парашут и волейбол. Хотел Krizantem се намира на 1,5 километра от центъра на Алания.</p><p>Концепция на хотела</p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1377/BIG_691246415_17652859491377.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1377/BIG_691246415_17652859491377.jpg","https://static.peakview.bg/img/data2/121/hoteli/1377/BIG_691246315_17652859491377.jpg","https://static.peakview.bg/img/data2/121/hoteli/1377/BIG_692081212_17652859491377.jpg","https://static.peakview.bg/img/data2/121/hoteli/1377/BIG_692081216_17652859491377.jpg","https://static.peakview.bg/img/data2/121/hoteli/1377/BIG_692081230_17652859491377.jpg","https://static.peakview.bg/img/data2/121/hoteli/1377/BIG_691246154_17652859491377.jpg","https://static.peakview.bg/img/data2/121/hoteli/1377/BIG_642122091_17652859491377.jpg","https://static.peakview.bg/img/data2/121/hoteli/1377/BIG_691246312_17652859491377.jpg","https://static.peakview.bg/img/data2/121/hoteli/1377/BIG_691246353_17652859491377.jpg","https://static.peakview.bg/img/data2/121/hoteli/1377/BIG_691246189_17652859491377.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>SUN HEAVEN QUEEN HOTEL се намира в Конаклъ.</p><p>Хотелът се състои от една 6-етажна сграда с общо 110 стаи с площ 3000 кв.м.</p><p>Хотелът е построен през 1993 г., последно реновиран през 2017 г.</p><p>Централната част на Конаклъ е на 6,1 км. Международното летище Gazipasa е на 60 километра.</p><p>Хотелът се намира на първа линия, на 100 м от собствения пясъчно-чакълест плаж на хотела.</p><p><strong>В стаите:</strong>В стаите:</p><p>Стаите разполагат с:</p><p>балкон</p><p>под: керамични плочки</p><p>мини бар (празен)</p><p>телефон</p><p>Телевизор</p><p>смяна на спално бельо: 3 пъти седмично</p><p>почистване на стаите: 3 пъти седмично</p><p>сейф: в стаята, срещу заплащане</p><p>климатик: индивидуален</p><p>душ</p><p>сешоар: да</p><p>Видове стаи в хотела:</p><p>110 стандартни стаи (макс. 3+ бебе. човека, 27 м2)</p><p>10 Стандартна стая без балкон (макс. 2 човека, 22 м2)</p><p><strong>На територията на хотела: </strong>На територията на хотела:</p><p>Основен ресторант (шведска маса)</p><p>A'la carte ресторант (рибен - платен): 19:15-21:00ч.</p><p>Бар обслужване: по време на обяд и вечеря.</p><p>Лоби бар: 09:30-23:00ч.</p><p>Бар на басейна: 11:00-18:30ч.</p><p>на басейна шезлонги, матраци: безплатно</p><p>1 външен басейн 160 кв.м, отворен от 08:00-19:00 часа</p><p>1 външен басейн за деца, 17 кв.м.</p><p>водни пързалки: 1</p><p>фризьор (хотел B CLUB SUN HEAVEN FAMILY&SPA)</p><p>пералня</p><p>SPA-център</p><p>лекарски кабинет</p><p>Wi-Fi в общите части, безплатно</p><p>магазини (в хотел B CLUB SUN HEAVEN FAMILY&SPA)</p><p>водни спортове срещу заплащане</p><p>тенис на маса безплатно</p><p>Турска баня (хамам) срещу заплащане (в хотел B CLUB SUN HEAVEN FAMILY&SPA)</p><p>анимация безплатно</p><p>масаж срещу заплащане</p><p>безплатно аеробика</p><p>сауна срещу заплащане (в хотел B CLUB SUN HEAVEN FAMILY&SPA)</p><p>безплатен плажен волейбол</p><p>парна баня срещу заплащане</p><p>За деца:</p><p>има детски клуб (4-12 години)</p><p>детски басейн: да (1)</p><p>детегледачка: срещу заплащане</p><p><strong>Хранене:</strong>Хотелът функционира на база Ultra All Inclusive и предлага закуска, обяд и вечеря на блок маса, допълнителни закуски и неограничена консумация на местни алкохолни и безалкохолни напитки.</p><p>Всички вносни и бутилирани напитки се предлагат срещу допълнително заплащане. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/34/BIG_original1_158106942134.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/34/BIG_original1_158106942134.jpg","https://static.peakview.bg/img/data2/121/hoteli/34/BIG_1_158106942134.jpg","https://static.peakview.bg/img/data2/121/hoteli/34/BIG_12_158106942134.jpg","https://static.peakview.bg/img/data2/121/hoteli/34/BIG_22_158106942134.jpg","https://static.peakview.bg/img/data2/121/hoteli/34/BIG_123_158106942134.jpg","https://static.peakview.bg/img/data2/121/hoteli/34/BIG_654_158106942134.jpg","https://static.peakview.bg/img/data2/121/hoteli/34/BIG_852_158106942134.jpg","https://static.peakview.bg/img/data2/121/hoteli/34/BIG_8520_158106942134.jpg","https://static.peakview.bg/img/data2/121/hoteli/34/BIG_original_158106942134.jpg","https://static.peakview.bg/img/data2/121/hoteli/34/BIG_original00_158106942134.jpg","https://static.peakview.bg/img/data2/121/hoteli/34/BIG_original3_158106942134.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира на 100 км. от летище Анталия, на 110 км. от центъра на Анталия, на 20 км. от гр.Алания. Построен през 2013 г. с площ от 18 000 м2. Хотелът разполага общо с 290 стаи, от които 107 стандартни стаи и 180 фамилни стаи.</p><p><strong>В стаите:</strong>Всички стаи са оборудвани с: климатик, сателитна телевизия, телефон, баня с вана, сешоар, минибар (платен), сейф (платен), балкон. Почистване на стаите – всеки ден, смяна на бельото и кърпите – 3 пъти в седмицата.</p><p><strong>На територията на хотела: </strong>Основен ресторант, а - ла - карт ресторант (с предварителна резервация, заплаща се 5 евро на човек), 10 бара, 6 открити и 2 закрити басейна, водни пързалки, аквапарк, магазини, SPA център, дискотека, конферентна зала, паркинг.</p><p>За децата: Детска площадка, мини клуб (4-12 г.), 2 детски басейна, детска анимация.</p><p>Безплатни услуги: Турска баня, сауна, фитнес, дартс, тенис на маса, тенис корт, баскетбол, плажен волейбол, аеробика, водна гимнастика, жива музика, анимация, интернет.</p><p>Платени услуги: Масаж, фризьор, магазини, химическо чистене, лекар, водни спортове, наем на ракети и топки за тенис, осветление за тенис корта.</p><p>ПЛАЖ: Собствен – пясъчно / чакълест, на 600 м. от хотела. Чадъри и шезлонги на плажа и при басейна – безплатно, плажни кърпи – безплатно.</p><p><strong>Хранене:</strong>All Inclusive – закуска, обяд, вечеря и междинни хранения на шведска маса, местни алкохолни и безалкохолни напитки без лимит. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG_1678178356128.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG_1678178356128.jpg","https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG2_1678178358128.jpg","https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG3_1678178358128.jpg","https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG4_1678178359128.jpg","https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG5_1678178360128.jpg","https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG6_1678178361128.jpg","https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG7_1678178361128.jpg","https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG8_1678178362128.jpg","https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG9_1678178362128.jpg","https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG10_1678178363128.jpg","https://static.peakview.bg/img/data2/121/hoteli/128/BIG_IMG11_1678178364128.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е раположен на 100 км от летище Анталия, на 15 км от град Алания, на 300 м от плажа през пътя чрез подлез. </p><p>сновен ресторант, водни пързалки: 5, на басейна чадъри, шезлонги, матраци: безплатно; на басейна кърпи: срещу депозит, СПА център, 2 ресторанта а-ла-карт: (средиземноморски, османски - с предварителна резервация, за едноседмичен престой 1 посещение на един от ресторантите по избор - безплатно), 2 открити басейна, магазини, 2 конферентни зали (за 450-750 души), интернет Wi-Fi - платено, 1 закрит басейн (работи само през зимата), лекарски кабинет, пране, гладене</p><p>Безплатни Услуги:</p><p>тенис на маса, дартс, анимация, сауна, джакузи, волейбол на плажа, турска баня, парна баня, тенис оборудване под наем, фитнес, аеробика, дискотека, тенис корт (с тартаново покритие)</p><p>Платени Услуги:</p><p>билярд, водни спортове, масаж, игрални автомати, осветление на тенис корта, боулинг (2 пътеки)</p><p>Плаж:</p><p>Собствен плаж (пясък и чакъл). Бар на плажа: безплатно. Плажни кърпи: безплатно, срещу депозит. Плажни чадъри, шезлонги, матраци: безплатно.</p><p><strong>В стаите:</strong>room service: денонощно, почистване на стаите: ежедневно, централен климатик, интернет: Wi-Fi платен , смяна на спалното бельо: 3 пъти седмично, телефон, телевизия, душ, сейф в стаята, доплащане, сешоар, балкон, безплатен мини бар (безалкохолни напитки - в деня на пристигане, вода - всеки ден)</p><p><strong>На територията на хотела: </strong>Състои се от една 7-етажна сграда: 328 standard room (от тях 6 номера за инвалиди, макс. 3+1 чов., 24 м2), 82 двуетажни duplex family (на първо ниво: спалня без врати, на второ ниво: спалня, макс. 5 чов., 30 м2), 8 двустайни family suite (2 спални с врати, макс. 4 чов., 40 м2), 2 двуетажни duplex family suite (на първо ниво: хол, 2 спални с врати, на второ ниво: спалня, макс. 7 чов., 60 м2), 4 тристайни President suite (хол, 2 спални с врати, 2 бани, макс. 8 чов., 77 м2), 1 четиристаен King suite (хол, 3 спални с врати, работен кабинет, 2 бани, индивидуален климатик, макс. 10 чов., 140 м2)</p><p><strong>Хранене:</strong>Ultra All Inclusive </p><p>Хотелът има право да прави промени в концепцията, без да уведомява предварително туроператора за наложените промени. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_335010241_17679503431403.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_335010241_17679503431403.jpg","https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_335010502_17679503431403.jpg","https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_617654770_17679503431403.jpg","https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_769016173_17679503431403.jpg","https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_767909628_17679503431403.jpg","https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_335010362_17679503431403.jpg","https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_335010481_17679503431403.jpg","https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_335010342_17679503431403.jpg","https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_509497486_17679503431403.jpg","https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_335144514_17679503431403.jpg","https://static.peakview.bg/img/data2/121/hoteli/1403/BIG_335144773_17679503431403.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Club Paradiso се намира на хълм с изглед към Средиземно море. Град Алания е на около 7 км.</p><p><strong>В стаите:</strong>Стаи</p><p>Стаите разполагат с: самостоятелна баня с душ и WC, сешоар, климатик, телефон, телевизор с музикални програми, мини бар, сейф, балкон или тераса.</p><p><strong>На територията на хотела: </strong>В хотела</p><p>Хотелът разполага с огромен басейн, както и панорамна тераса за хранене. Предлага безплатен трансфер до частния плаж и няколко магазина на място. СПА център с пълен набор от услуги, като сауни, фитнес салон и масажни процедури. Налице е закрит басейн за по-хладните месеци, както и тенис кортове за лятото.</p><p><strong>Хранене:</strong>ИЗХРАНВАНЕ - UAI – Ултра всичко влючено</p><p>Закуска, късна закуска, обяд, вечеря, късна вечеря, сладки и сладолед в определени часове, снек, диетично и вегитарианско меню, 24 часа алкохолни и безалкохолни напитки местно производство. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1376/BIG_caption%20%281%29_17652847481376.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1376/BIG_caption%20%281%29_17652847481376.jpg","https://static.peakview.bg/img/data2/121/hoteli/1376/BIG_caption%20%283%29_17652847481376.jpg","https://static.peakview.bg/img/data2/121/hoteli/1376/BIG_caption_17652847481376.jpg","https://static.peakview.bg/img/data2/121/hoteli/1376/BIG_family-suit-room%20%281%29_17652847481376.jpg","https://static.peakview.bg/img/data2/121/hoteli/1376/BIG_family-suit-room_17652847481376.jpg","https://static.peakview.bg/img/data2/121/hoteli/1376/BIG_lobby_17652847481376.jpg","https://static.peakview.bg/img/data2/121/hoteli/1376/BIG_pool_17652847481376.jpg","https://static.peakview.bg/img/data2/121/hoteli/1376/BIG_pool-bridge_17652847481376.jpg","https://static.peakview.bg/img/data2/121/hoteli/1376/BIG_pool-restaurant_17652847481376.jpg","https://static.peakview.bg/img/data2/121/hoteli/1376/BIG_restaurant_17652847481376.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>THE NORA FAMILY CLUB 4*, познат до края на летния сезон на 2025 г. под името SCYLAX FAMILY CLUB 4*, е бюджетен хотел, разположен в района на Махмутлар, източно от централната част на Алания, на 50 метра от пясъчно-чакълестата плажна ивица на курорта. </p><p>Общата площ на комплекса е приблизително 130 000 м².</p><p><strong>В стаите:</strong>В стаите:</p><p>Сателитна телевизия, климатик, телефон, баня с душ или вана, сешоар, минибар, сейф.</p><p><strong>На територията на хотела: </strong>На територията на хотела:</p><p>Основен ресторант, бар, открит басейн, водни пързалки, детска площадка, SPA център.</p><p><strong>Хранене:</strong>Хранене:</p><p>All Inclusive – закуска, обяд и вечеря на блок маса, допълнителни закуски и безплатна консумация на местни алкохолни и безалкохолни напитки. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_433914507_17654586101383.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_433914507_17654586101383.jpg","https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_662059865_17654586101383.jpg","https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_642702671_17654586101383.jpg","https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_433914512_17654586101383.jpg","https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_133804953_17654586101383.jpg","https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_433914278_17654586101383.jpg","https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_433914437_17654586101383.jpg","https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_433914383_17654586101383.jpg","https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_662061751_17654586101383.jpg","https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_662062016_17654586101383.jpg","https://static.peakview.bg/img/data2/121/hoteli/1383/BIG_662062182_17654586101383.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Sey Beach Hotel & Spa се намира в Кестел, Алания, на 37 км от летище Газипаша и на 5 км от центъра на Алания. Разположен на 50 метра от морето, обектът е построен на площ от 3000 м2.</p><p><strong>В стаите:</strong>В стаите</p><p>Предлагайки общо 100 стаи, в които комфортът и елегантността са приоритет, обектът предлага много удобства като телевизор, мини бар, телефон, безжичен интернет, баня и тоалетна, сешоар. Standard room ( 19-26m2); Family room ( 32m2).</p><p><strong>На територията на хотела: </strong>На територията на хотела</p><p>Обектът предлага на гостите си незабравима почивка с много съоръжения като сауна, турска баня, фитнес център, анимация, тенис на маса, мини клуб и детски площадки.</p><p><strong>Хранене:</strong>ALL INCLUSIVE концепция. Един основен ресторант и 3 бара. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG_1637073431798.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG_1637073431798.jpg","https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG2_1637073432798.jpg","https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG3_1637073433798.jpg","https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG4_1637073434798.jpg","https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG5_1637073435798.jpg","https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG6_1637073436798.jpg","https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG7_1637073437798.jpg","https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG8_1637073438798.jpg","https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG9_1637073439798.jpg","https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG10_1637073440798.jpg","https://static.peakview.bg/img/data2/121/hoteli/798/BIG_IMG11_1637073441798.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е на 125 км от летище Анталия, само на 1 км от Алания и на 100 метра</p><p><strong>На територията на хотела: </strong>Всички стаи в Monte Carlo имат балкон с изглед към морето или басейна. Освен това те включват климатик и сателитна телевизия.</p><p>Плаж: Собственият пясъчно-чакълест плаж на хотела се намира на територията на обществения плаж, който е на 100 метра от хотела. Чадъри, шезлонги и матраци се предоставят безплатно.</p><p>За деца: Хотелът предлага открит плувен басейн, мини клуб за деца от 2 до 12 години, детско меню в ресторанта, детски столчета, детска площадка, развлекателни програми и бебешка кошара по заявка.</p><p><strong>Хранене:</strong>ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1381/BIG_291456111_17654425331381.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1381/BIG_291456111_17654425331381.jpg","https://static.peakview.bg/img/data2/121/hoteli/1381/BIG_291455672_17654425331381.jpg","https://static.peakview.bg/img/data2/121/hoteli/1381/BIG_6109986_17654425331381.jpg","https://static.peakview.bg/img/data2/121/hoteli/1381/BIG_20962465_17654425331381.jpg","https://static.peakview.bg/img/data2/121/hoteli/1381/BIG_6039809_17654425331381.jpg","https://static.peakview.bg/img/data2/121/hoteli/1381/BIG_47000078_17654425331381.jpg","https://static.peakview.bg/img/data2/121/hoteli/1381/BIG_394021898_17654425331381.jpg","https://static.peakview.bg/img/data2/121/hoteli/1381/BIG_613391767_17654425331381.jpg","https://static.peakview.bg/img/data2/121/hoteli/1381/BIG_394008484_17654425331381.jpg","https://static.peakview.bg/img/data2/121/hoteli/1381/BIG_389643137_17654425331381.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е разположен на залива Фугла в курортното селище Тюрклер, на 98 километра от международното летище на Анталия, на 26 километра западно от центъра на град Алания и на приблизително 200 метра от морския бряг.</p><p><strong>В стаите:</strong>В стаите:</p><p>Стандартните двойни стаи са оборудвани с индивидуален климатик, LCD телевизор със сателитен приемник, телефон с директно избиране, баня с душ или вана, телефон в банята, сешоар, минибар, сейф, кресло, балкон.</p><p><strong>На територията на хотела: </strong>На територията на хотела:</p><p>Основен ресторант, 3 а-ла-карт ресторанта, 5 бара и снекбар, дискотека, 2 открити басейна, водни пързалки, детски басейн, мини клуб, SPA център със закрит басейн, турска баня и сауна, фитнес зала, анимационна програма, вечерни представления, спортни и развлекателни дейности, търговски център, конферентна зала.</p><p>Безплатни услуги: фитнес зала, всички дейности от анимационната програма, дартс, тенис на маса, тенис на корт в светлата част от деня, чадъри, шезлонги и матраци на плажа и при басейните, плажни кърпи.</p><p>Платени услуги: масажи и други козметични процедури, телефон и факс, магазини, интернет кафе, пералня и гладене, медицински услуги, ползване на сейфа в стаята, наем на лек автомобил, тийн клуб, рум сървиз.</p><p>За децата: детска площадка, мини клуб, детска анимация, детски басейн, водни пързалки.</p><p><strong>Хранене:</strong>Хранене:</p><p>Хотелъг функционира на база All Inclusive, включваща закуска, обяд и вечеря на блок маса в основния ресторант, допълнителни закуски и неограничена консумация на местни алкохолни и безалкохолни напитки.</p><p>Допълнително се заплаща за консумация на бутилирани и вносни алкохолни и безалкохолни напитки.</p><p>Концепцията включва едно безплатно посещение на избран а-ла-карт ресторант – със задължителна предварителна резервация! </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1379/BIG_ana_17652868831379.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1379/BIG_ana_17652868831379.jpg","https://static.peakview.bg/img/data2/121/hoteli/1379/BIG_11_17652868831379.jpg","https://static.peakview.bg/img/data2/121/hoteli/1379/BIG_beach_17652868831379.jpg","https://static.peakview.bg/img/data2/121/hoteli/1379/BIG_ana-gun_17652868831379.jpg","https://static.peakview.bg/img/data2/121/hoteli/1379/BIG_mtVit_17652868831379.jpg","https://static.peakview.bg/img/data2/121/hoteli/1379/BIG_P5xxY_17652868831379.jpg","https://static.peakview.bg/img/data2/121/hoteli/1379/BIG_restoran_17652868831379.jpg","https://static.peakview.bg/img/data2/121/hoteli/1379/BIG_standart-oda-1-scaled-1_17652868831379.jpg","https://static.peakview.bg/img/data2/121/hoteli/1379/BIG_FAM-A-11-scaled-1_17652868831379.jpg","https://static.peakview.bg/img/data2/121/hoteli/1379/BIG_4444444_17652868831379.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Разположение</p><p>Намира се на 110 км от летище Анталия, на 120 км от центъра на Анталия, на 12км от центъра на Алания, на 1 км от селището Конаклъ, на брега на морето. Построен 2005 г. на обща площ от 17 000 м2. Последно реновиран 2021г.</p><p><strong>В стаите:</strong>В стаите</p><p>Хотелът разполага с общо 325 стаи, разположени в една основна 5-етажна сграда Main Building и една 5-етажна сграда Anex Building.</p><p>Стаи Main Building: 255 Standard Room (изглед градина или басейн, 26 м2)</p><p>Стаи Anex Building: 40 Fam A Room (спалня и всекидневна, изглед градина или басейн - 38 м2 ) , 26 Fam B Room (спалня и всекидневна, изглед градина или басейн – 55 м2), 2 Room Fam A (спалня и всекидневна, изглед градина или басейн – 38 м2), 2 Room Fam B (спалня и всекидневна, изглед градина или басейн – 55 м2).</p><p>Всички стаи са оборудвани с телевизор, телефон, сешоар, чехли, минибар (безплатен при пристигане, след това се зарежда само с вода), сейф (безплатен).</p><p>Почистване на стаите – всеки ден, смяна на кърпите и спалното бельо – 2 пъти в седмицата.</p><p><strong>На територията на хотела: </strong>На територията на хотела</p><p>Основен ресторант, снек бар, гьозлеме, сладкарница, кафетерия, 5 бара, диско бар, 3 открити и 1 закрит (неотопляем) басейн, аквапарк, 2 конферентни зали, СПА център, магазини, паркинг.</p><p>За децата: Мини клуб (4-1г.), открит и закрит (неотопляем) детски басейн, детска площадка, игрална зона, детска анимация, столче за хранене, детска количка – срещу заплащане.</p><p>Безплатни услуги: Сауна, турска баня, парна баня, фитнес, дартс, мини футбол, тенис на маса, анимация, плажен волейбол, баскетбол, аеробика, водна гимнастика, анимация, библиотека, Wi-Fi (в лоби).</p><p>Платени услуги: Масаж, пилинг, фризьор, фотограф, лекар, игрална зала, билярд, химическо чистене, водни спортове.</p><p><strong>Хранене:</strong>Хранене</p><p>Ultra All Inclusive - закуска, обяд и вечеря на шведска маса, междинни хранения, алкохолни и безалкохолни напитки - без лимит (съгласно концепцията на хотела). </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m1_17528236501156.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m1_17528236501156.jpg","https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m3_17528236501156.jpg","https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m4_17528236501156.jpg","https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m5_17528236501156.jpg","https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m6_17528236501156.jpg","https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m7_17528236501156.jpg","https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m8_17528236501156.jpg","https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m9_17528236501156.jpg","https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m10_17528236501156.jpg","https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m11_17528236501156.jpg","https://static.peakview.bg/img/data2/121/hoteli/1156/BIG_m12_17528236501156.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Намира се на адрес Talip Kahraman Caddesi, Konaklı, Alanya, Турция</p><p>Намира се на 110 км. от летище Анталия, на 100 км. от центъра на Анталия, на 12 км. от центъра на Алания, на 2 км. от селището Конакль.</p><p>Построен през 2007г. с обща площ 9.000 м2, реновиран през 2020г.</p><p><strong>В стаите:</strong>Разполага с 240 стаи, включително стандартни двойни, фамилни и свързващи помещения, с изглед към градина или басейн .Всяка стая включва климатик, минибар, сейф, балкон и баня с тоалетни принадлежности.Всички стаи са оборудвани с климатик, телевизор, телефон, баня с вана, сешоар, минибар (вода, безалкохолни напитки – само при пристигане), сейф (безплатен). Почистване на стаите – всеки ден, смяна на кърпите – при поискване, смяна на спалното бельо – 2 пъти в седмицата.</p><p><strong>На територията на хотела: </strong>Басейни: служебен открит, детски басейн, закрит отопляем басейн, аквапарк с водни пързалки .</p><p>СПА и уелнес: сауна, масажи (тайландски, спортни, масажи с горещи камъни), фитнес център .</p><p>Спорт и забавление: тенис корт, тенис на маса, дартс, развлекателна програма, караоке, игри и музика</p><p>За деца: детски клуб, детски басейн, площадка, аквапарк с водна пързалка, анимация, вечерни забавления, мини клуб – частично срещу допълнително заплащане .</p><p><strong>Хранене:</strong>All Inclusive – закуска, обяд и вечеря на шведска маса, междинни хранения, местни алкохолни и безалкохолни напитки – без лимит (съгласно концепцията на хотела). </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG_158099498951.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG_158099498951.jpg","https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG2_158099499051.jpg","https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG3_158099499051.jpg","https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG4_158099499151.jpg","https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG5_158099499151.jpg","https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG6_158099499251.jpg","https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG7_158099499351.jpg","https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG8_158099499351.jpg","https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG9_158099499451.jpg","https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG10_158099499451.jpg","https://static.peakview.bg/img/data2/121/hoteli/51/BIG_IMG11_158099499551.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е разположен на 110 км. от летище Анталия, на 18 км.от гр. Алания, на 50 м. от морския бряг, с обща площ от 37.700 м2 в район Конаклъ отстоящ на 4 км от хотела.</p><p><strong>В стаите:</strong>Хотелът предлага настаняване в стандартни и фамилни стаи. Стандартните стаи /общо 219 бр./ са с големина от 28 кв.м. Фамилните стаи /общо159 бр./ са с площ от 39 кв.м. и 58 кв.м. В тях се приема настаняване до 2+2 /станд.стаи, или 3+1/ фам. стаи. Всяка стая разполага с климатик, сателитна телевизия, телефон, баня с душ или вана, сешоар, под ламинат, мини бар (безплатно), сейф (платено), балкон. Почистване на стаите - всеки ден, смяна на бельото и кърпите 3 пъти в седмицата.</p><p><strong>На територията на хотела: </strong>„Eftalia Village” разполага с 12 сгради /тип 3-етажни корпуса/, общо с 425 стаи, от които 266 стандартни стаи и 159 фамилни стаи. Добре озеленен хотел, намиращ се точно срещу новия Аквапарк - ISLAND. Покрай хотела преминава основния, първокласен път свързващ Анталия с Алания.</p><p>Удобства:</p><p>Основен ресторант, 2 А-Ла-Карт ресторанта (Османски и италиански с предварителна резервация ,по едно посещение във всеки от тях-безплатно), 5 бара, патисерия и кафе,дискотека, 2 открити /единия само за възрастни/ и 2 закрити басейна, детски басейн, водни пързалки, аквапарк с 4 пързалки за възрастни и 3 за деца, амфитеатър, магазини, СПА център.</p><p>Безплатни Услуги:</p><p>Турска баня, сауна, фитнес, дартс, тенис на маса, тенис корт, баскетбол, плажен волейбол, анимация, жива музика и шоу програми, интернет само около рецепция, детски басейн, водни пързалки, мини клуб (4 - 12 г.), детска анимация, джуниор клуб (3-16г.).</p><p>Платени Услуги:</p><p>Масаж, билярд, лекар, химическо чистене, магазини, водни спортове, фрешове, рент-а-кар, детски колички, интернет - само на рецепция.</p><p>Плаж:</p><p>Собствен, пясъчно - чакълест. Чадъри и шезлонги на плажа и при басейна - безплатно. Плажни кърпи-безплатно, замяната се заплаща.</p><p><strong>Хранене:</strong>ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG_1678178106134.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG_1678178106134.jpg","https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG2_1678178107134.jpg","https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG3_1678178108134.jpg","https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG4_1678178108134.jpg","https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG5_1678178109134.jpg","https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG6_1678178110134.jpg","https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG7_1678178110134.jpg","https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG8_1678178111134.jpg","https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG9_1678178112134.jpg","https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG10_1678178112134.jpg","https://static.peakview.bg/img/data2/121/hoteli/134/BIG_IMG11_1678178114134.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира в Пайалар на 15 км от център Алания и разполага със СПА център, и собствен плаж.</p><p>Официално е открит през 2017 г. върху площ от 11 000 кв.м.</p><p><strong>В стаите:</strong>В стаите:</p><p>Хотелът представлява два шестетажни масивни корпуса разполагащи с 332 стаи. Основния блок се състои от 243 Standart Room, 15 Duplex Room, 5 Deluxe Suit. Вторият корпус се състои от 50 Standart Room. Обособени са и 3 стаи за хора със специялни нужди.</p><p>Standart room са с площ от 28 кв.м. Разполагат с двойно легло, или две единични легла, диван, тоалетна, душ кабина, сешоар, сателитна телевизия, LCD телевизор, телефон, сейф, минибар – запълва се веднъж при настаняване, централен климатик, ламиниран паркет и тераса.</p><p>Duplex room са с площ от 56 кв.м и са на два етажа. Разполагат с едно двойно легло на първи етаж и две единични на втори етаж, както и диван. Всеки етаж има самостоятелен санитарен възел и баня, сешоар, сателитна телевизия, LCD телевизор, телефон, сейф, минибар – запълва се веднъж при настаняване, централен климатик, ламиниран паркет и тераса.</p><p>Deluxe Suite са с площ от 57 кв.м. Състоят се от една спалня, една дневна, джакузи, тоалетна, душ кабина, сешоар, сателитна телевизия, LCD телевизор, телефон, сейф, минибар – запълва се веднъж при настаняване, централен климатик, ламиниран паркет и просторна тераса.</p><p>Suit room са с площ от 50 кв.м. Състоят се от една спалня, тоалетна, душ кабина, сешоар, сателитна телевизия, LCD телевизор, телефон, сейф, минибар – запълва се веднъж при настаняване, централен климатик, ламиниран паркет и просторна тераса.</p><p>Large Standart Room площ от 32 кв.м. Разполагат с двойно легло, или две единични легла, диван, тоалетна, душ кабина, сешоар, сателитна телевизия, LCD телевизор, телефон, сейф, минибар – запълва се веднъж при настаняване, централен климатик, ламиниран паркет и тераса.</p><p>Ежедневно почистване на стаите. Смяна на спалното бельо на всеки два дни. Смяна на кърпите в банята – по желание на гостите.</p><p><strong>На територията на хотела: </strong>В хотела:</p><p>• Основен ресторант;</p><p>• Ресторант на плажа;</p><p>• А-ла-карт ресторант;</p><p>• Сладкарница;</p><p>• Лоби бар;</p><p>• 5 бара;</p><p>• Дискотека;</p><p>• 2 открити басейна;</p><p>• 2 детски басейна;</p><p>• 2 вътрешни басейна;</p><p>• SPA център;</p><p>• Целодневна анимационна програма, вечерни представления;</p><p>• Конферентни зали;</p><p>• Безжичен интернет на лоби;</p><p>• Паркинг.</p><p>За децата:</p><p>Мини клуб, детска анимация, мини дискотека, детски басейни.</p><p>Безплатни Услуги:</p><p>Турска баня, парна баня и сауна, фитнес, всички дейности от анимационната програма, чадъри и шезлонги на плажа и при басейните, безжичен интернет в лоби.</p><p>Платени Услуги:</p><p>Масажи и други козметични процедури, пералня, лекар, ползване на сейф в стаята, всички водни спортове, room service.</p><p>Плаж:</p><p>Собствен пясъчно - чакълест, отдалечен на приблизително 250 м от сградата на хотела, до който се стига посредством подземен тунел.</p><p>Безплатно ползване на чадъри, шезлонги и матраци на плажа и при басейните.</p><p><strong>Хранене:</strong>Хотелът фунционира на база Ultra All Inclusive, включваща закуска, обяд и вечеря на блок маса в основния ресторант, допълнителни закуски и неограничена консумация на местни алкохолни и безалкохолни напитки в часовия интервал 10:00-01:00 ч.</p><p>Концепцията включва едно безплатно посещение на а-ла-карт ресторанта при 7 пълни нощувки, като се изисква предварителна резервация. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_1_17603494361234.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_1_17603494361234.jpg","https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_3_17603494361234.jpg","https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_4_17603494361234.jpg","https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_5_17603494361234.jpg","https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_6_17603494361234.jpg","https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_7_17603494361234.jpg","https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_8_17603494361234.jpg","https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_9_17603494361234.jpg","https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_11_17603494361234.jpg","https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_10_17603494361234.jpg","https://static.peakview.bg/img/data2/121/hoteli/1234/BIG_12_17603494361234.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Senza Sunset Beach Hotel се намира в курорта Алания, в района Конаклъ, на първа линия до морето. Хотелът разполага със собствен пясъчно-чакълест плаж и е на около 12 км от центъра на Алания и ~110 км от летище Анталия</p><p><strong>В стаите:</strong>Standard Room, Family Room, Sea View Room</p><p>Всички стаи са оборудвани с:</p><p>Климатик</p><p>Телевизор с плосък екран</p><p>Минибар</p><p>Баня с душ и сешоар</p><p>Балкон с изглед към градина, басейн или море</p><p><strong>На територията на хотела: </strong>Категория: 5 звезди</p><p>Открит басейн, детски басейн, водни пързалки</p><p>СПА център – турска баня, сауна, масажи</p><p>Фитнес, анимация, вечерни шоу програми</p><p>Частен плаж с чадъри и шезлонги</p><p>Безплатен Wi-Fi в общите части, 24/7 рецепция, обменно бюро</p><p><strong>Хранене:</strong>All Inclusive</p><p>Закуска, обяд и вечеря на шведска маса</p><p>Местни алкохолни и безалкохолни напитки от 10:00 до 23:00</p><p>Снек бар, бар край басейна, бар на плажа</p><p>Възможност за вегетариански и халал менюта </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/996/BIG_1_1709630904996.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/996/BIG_1_1709630904996.jpg","https://static.peakview.bg/img/data2/121/hoteli/996/BIG_3_1709630904996.jpg","https://static.peakview.bg/img/data2/121/hoteli/996/BIG_4_1709630904996.jpg","https://static.peakview.bg/img/data2/121/hoteli/996/BIG_5_1709630904996.jpg","https://static.peakview.bg/img/data2/121/hoteli/996/BIG_6_1709630904996.jpg","https://static.peakview.bg/img/data2/121/hoteli/996/BIG_7_1709630904996.jpg","https://static.peakview.bg/img/data2/121/hoteli/996/BIG_8_1709630904996.jpg","https://static.peakview.bg/img/data2/121/hoteli/996/BIG_9_1709630904996.jpg","https://static.peakview.bg/img/data2/121/hoteli/996/BIG_10_1709630904996.jpg","https://static.peakview.bg/img/data2/121/hoteli/996/BIG_11_1709630904996.jpg","https://static.peakview.bg/img/data2/121/hoteli/996/BIG_12_1709630904996.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е разположен на 110 км от международното летище на Анталия, на 13 км западно от град Алания, на 200 м. от селището Конаклъ, на брега на морето.</p><p>Построен е през 1990 г., обща площ 20 000 кв. м., последно реновиран през 2013 г.</p><p><strong>В стаите:</strong>Състои се от един 6-етажен корпус с общо 294 стаи, сред които 197 стандартни стаи, 95 фамилни стаи и 2 стаи за инвалиди.</p><p>душ</p><p>сешоар</p><p>индивидуален климатик</p><p>телевизор</p><p>телефон</p><p>мини-бар (вода се допълва ежедневно, безплатно)</p><p>сейф (безплатно)</p><p>балкон</p><p>ежедневно почистване на стаята</p><p>смяна на спалното бельо - 3 пъти седмично</p><p>безжичен интернет (безплатно)</p><p><strong>На територията на хотела: </strong>В ХОТЕЛА</p><p>Хотелът разполага с:</p><p>основен ресторант</p><p>а ла карте ресторант (международен с предварителна резервация, за целия престой едно безплатно посещение, деца до 12 години не се допускат)</p><p>3 бара</p><p>2 открити басейна</p><p>закрит басейн</p><p>3 водни пързалки</p><p>лекар на повикване</p><p>СПА център (платено)</p><p>фризьорски салон (платено)</p><p>пералня (платено)</p><p>химическо чистене (платено)</p><p>2 конферентни зали</p><p>Собствен плаж с пясък/чакъл.</p><p>Бар на плажа: използване на снек-бара.</p><p>На плажа и при басейна: чадъри, шезлонги, матраци – безплатно.</p><p>Плажни кърпи: безплатно.</p><p><strong>Хранене:</strong>Хотелът функционира на база Ultra All Inclusive, включваща закуска, обяд и вечеря на блок маса в основния ресторант, допълнителни закуски и неограничена консумация на местни алкохолни и безалкохолни напитки.</p><p>Допълнително се заплаща за консумация на бутилирани и вносни алкохолни и безалкохолни напитки. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG_1678177775586.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG_1678177775586.jpg","https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG2_1678177777586.jpg","https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG3_1678177777586.jpg","https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG4_1678177778586.jpg","https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG5_1678177779586.jpg","https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG6_1678177780586.jpg","https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG7_1678177781586.jpg","https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG8_1678177781586.jpg","https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG9_1678177782586.jpg","https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG10_1678177783586.jpg","https://static.peakview.bg/img/data2/121/hoteli/586/BIG_IMG11_1678177783586.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира на 100 км. от летище Анталия, на 110 км. от центъра на гр.Анталия, на 17км. от гр.Алания, на брега на морето. Построен през 2011 г. с обща площ от 38 500 м2. Реновиран 2020г.</p><p><strong>В стаите:</strong>Хотелът разполага общо с 470 стаи, от които 310 стандартни стаи и 124 фамилни стаи. Всички стаи са оборудвани с: климатик, сателитна телевизия, телефон, баня с вана, сешоар, мини бар (вода и безалкохолни наппитки), сейф, балкон. Почистване на стаите – всеки ден, смяна на бельото и кърпите – 3 пъти в седмицата.</p><p><strong>На територията на хотела: </strong>В хотела:</p><p>Основен ресторант, 2 а - ла - карт ресторанта (с предварителна резервация), 7 бара, 1 открити и 1 закрит басейна, водни пързалки, аквапарк – Eftalia Island, магазини, SPA център, дискотека, конферентна зала, паркинг.</p><p>За децата:</p><p>Детска площадка, мини клуб (4-12 г.), 2 детски басейна, водни пързалки. </p><p>Безплатни Услуги:</p><p>Турска баня, фитнес, дартс, тенис на маса, тенис корт, баскетбол, плажен волейбол, аеробика, жива музика, анимация, интернет.</p><p>Платени Услуги:</p><p>Сауна, Масаж, фризьор, магазини, билярд, интернет кафе, компютърни и видеоигри, лекар, уроци по тенис, водни спортове.</p><p>Плаж:</p><p>Собствен, пясъчен. Чадъри, шезлонги и матраци на плажа и при басейна – безплатно.</p><p><strong>Хранене:</strong>ULTRA ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/874/BIG_1-Hotel-4_1675848993874.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/874/BIG_1-Hotel-4_1675848993874.jpg","https://static.peakview.bg/img/data2/121/hoteli/874/BIG_1-Hotel-1_1675848993874.jpg","https://static.peakview.bg/img/data2/121/hoteli/874/BIG_1-Hotel-7_1675848993874.jpg","https://static.peakview.bg/img/data2/121/hoteli/874/BIG_1-Hotel-8-1_1675848993874.jpg","https://static.peakview.bg/img/data2/121/hoteli/874/BIG_1-Hotel-9_1675848993874.jpg","https://static.peakview.bg/img/data2/121/hoteli/874/BIG_1-Hotel-11_1675848993874.jpg","https://static.peakview.bg/img/data2/121/hoteli/874/BIG_12-Plaj-Yolu-2_1675848993874.jpg","https://static.peakview.bg/img/data2/121/hoteli/874/BIG_11-Garden-1_1675848993874.jpg","https://static.peakview.bg/img/data2/121/hoteli/874/BIG_6-Hotel-beach-1_1675848993874.jpg","https://static.peakview.bg/img/data2/121/hoteli/874/BIG_6-Hotel-beach-3_1675848993874.jpg","https://static.peakview.bg/img/data2/121/hoteli/874/BIG_6-Hotel-beach-6_1675848993874.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира в района на Конаклъ, на 110 километра от международното летище на Анталия, на 12 километра от централната градска част на Алания и на приблизително 150 метра от брега на морето, с площ от 9500 m².</p><p><strong>В стаите:</strong>Хотелът се състои от две пететажани основни сгради и разполага с общо 299 стаи.</p><p>Всички стаи са оборудвани с индивидуален климатик, LCD телевизор със сателитен приемник, телефон с директно избиране, баня с душ или вана, сешоар, минибар (ежедневно презареждан с вода), сейф - срещу заплащане, безжичен интернет Wi-fi - срещу заплащане, балкон.</p><p>Ежедневно почистване на стаите, смяна на спалното бельо и кърпите – два пъти в седмицата.</p><p><strong>На територията на хотела: </strong>Основен ресторант, 4 бара, гьозлеме, 2 открити басейна, водни пързалки, SPA център с турска баня и сауна, фитнес зала, анимационна програма, тенис на маса, дартс, плажен волейбол, водна топка, аеробика, водна гимнастика, вечерни представления, дискотека, безжичен интернет Wi-fi само срещу заплащане, паркинг, конферентна зала.</p><p>За децата: детска площадка, мини клуб 4-12г., мини дискотека, детски басейн.</p><p>Платени услуги: масажи, водни спортове, Wi-fi интернет, напитки в дискотеката.</p><p>Плаж:</p><p>Собствена пясъчно-чакълест плажна ивица, на 150 метра от хотела, със снекбар на плажа. Безплатно ползване на чадъри, шезлонги и матраци на плажа и при басейните.</p><p>Хотелът предоставя плажни кърпи срещу допълнително заплащане. Общ плаж с хотел Caretta Beach</p><p><strong>Хранене:</strong>All Inclusive </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1313/BIG_1_17643368611313.png"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1313/BIG_1_17643368611313.png","https://static.peakview.bg/img/data2/121/hoteli/1313/BIG_2_17643369221313.png"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира на 12 км от Алания, на 2 км от село Конакли, срещу собствен плаж.</p><p><strong>В стаите:</strong>Хотелът разполага с 409 стаи. Състои се от три нови шест-етажни сгради (2015 и 2020 г.) и три допълнителни постройки.</p><p>Стаите разполагат с: сплит климатик, телевизор, Wi-Fi (платен), минибар (вода всеки ден), комплект за приготвяне на чай и кафе, телефон, сейф (срещу допълнително заплащане), душ, домашни пантофи, продукти за баня, сешоар, Почистване: ежедневно. Смяна на спално бельо: 3 пъти седмично.</p><p><strong>На територията на хотела: </strong>Хотелът разполага с всичко необходимо за комфортен престой на гостите: ресторант, барове, басейн, анимация през деня и развлекателни мероприятия вечер. За децата има мини клуб и анимационна програма. Препоръчва се за семейна, активна почивка.</p><p>Хотелът е открит през 1996 г. (нови сгради са построени през 2015 г. и 2020 г.) Последната реновация е извършена през 2019 г. Общата площ е 22 000 m².</p><p>Собственият пясъчно-чакълест плаж е на 50 м от хотела, през пътя.</p><p>Шезлонги, чадъри — безплатно, плажни кърпи — с депозит, срещу заплащане.</p><p>Павилионите на плажа са платени. Влизане в морето - пясък, камъчета.</p><p><strong>Хранене:</strong>Ultra All Inclusive </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_536435111_17652864801378.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_536435111_17652864801378.jpg","https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_36440233_17652864801378.jpg","https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_10075806_17652864801378.jpg","https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_66596013_17652864801378.jpg","https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_66594327_17652864801378.jpg","https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_536436321_17652864801378.jpg","https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_66599450_17652864801378.jpg","https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_66597608_17652864801378.jpg","https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_66597852_17652864801378.jpg","https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_14985581_17652864801378.jpg","https://static.peakview.bg/img/data2/121/hoteli/1378/BIG_13382778_17652864801378.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Намира се на 120 км от летище Анталия и на 40 км от летище Gazipaşa, само на 50 м от плаж Клеопатра, където притежава собствен плаж. Центърът на Алания се намира на 1 км от хотела и до него се стига лесно с общетвен транспорт или такси. Построен през 2010г върху обща площ от 7.500 m², хотелът се състои от 7 отделни сгради и разполага с общо 293 стаи. Последно реновиран през 2020г.</p><p><strong>В стаите:</strong>В стаите</p><p>Хотелът разполага с общо 293 стандартни и фамилни стаи, разположени в общо 7 отделни 5 и 6-етажни сгради, свързани помежду си с мостчета. Всички стаи са с ламинат и балкон и са оборудвани с климатик, телевизор, телефон, баня с душ, сешоар, минибар (безплатно зареждане с вода), ползване на сейф (срещу доплащане). Wi-Fi интернет в стаите - срещу доплащане. Почистване на стаите - всеки ден; смяна на хавлии - през 2 дни; смяна на спалното бельо - 3 пъти в седмицата.</p><p><strong>На територията на хотела: </strong>На територията на хотела</p><p>На територията на хотела има основен ресторант, лоби бар и пул бар; фитнес център и сауна/ хамам се ползват безплатно от гостите на хотела. 1 външен и 1 вътрешен басейн (отопляем само през зимния период); 1 външен и 1 вътрешен детски басейн.</p><p>Безплатни услуги: Сауна, хамам, фитнес, тенис на маса, плажен волейбол, Wi-Fi (в лоби). Платени услуги: Масаж, фризьор, пране и гладене, лекар, билярд, водни спортове.</p><p>ПЛАЖ: Собствен. Чадъри и шезлонги на плажа - срещу заплащане; при басейна – безплатно. Плажни кърпи – срещу депозит.</p><p><strong>Хранене:</strong>Хранене</p><p>ALL INCLUSIVE - закуска, обяд и вечеря, междинни хранения, местни алкохолни и безалкохолни напитки (съгласно концепцията на хотела от 7:30 до 24:00ч).</p><p>Фрешове, турско кафе, както и вносни, бутилирани напитки са срещу допълнително заплащане. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1322/BIG_1_17643411061322.png"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1322/BIG_1_17643411061322.png","https://static.peakview.bg/img/data2/121/hoteli/1322/BIG_4_17643411621322.png","https://static.peakview.bg/img/data2/121/hoteli/1322/BIG_2_17643412071322.png"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Разположен е в района на Конакли, на 12 км от центъра на Алания, на 120 км от летище Анталия.</p><p>Построен през 2009 г с обща площ от 10 000 кв.м., реновиран е през 2015 г.</p><p><strong>В стаите:</strong>Хотелът разполага общо с 223 стаи разположени в 5-етажна сграда с два асансьора и четири двуетажни вили</p><p>Всички стаи са оборудвани с индивидуален климатик, сателитна телевизия, телефон с директно избиране, баня с душ или вана, сешоар, минибар, сейф, електрическа кана, балкон.</p><p> Почистване на стаите- всеки ден.Смяна на спалното бельо и кърпи – веднъж на всеки два дни.</p><p><strong>На територията на хотела: </strong>Основен ресторант, 1 а-ла-карт ресторант- италиански, 4 бара, 2 открити басейна, СПА център със закрит басейн, турска баня и сауна, анимационна програма, амфитеатър за вечерни представления, спортни и развлекателни дейности.</p><p>За деца хотелът разполага с детска площадка и мини клуб с детски аниматори.</p><p>Собствен скалист плаж, разположен на 250 м от територията на хотела през път. Чадъри, шезлонги, матраци при плажа и басейна- безплатно. Плажни кърпи-срещу депозит. На плажа има бар.</p><p><strong>Хранене:</strong>All Inclusive – закуска, обяд и вечеря с включени междинни хранения, алкохолни и безалкохолни напитки - без лимит (съгласно концепцията на хотела). </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1222/BIG_1_17593219121222.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1222/BIG_1_17593219121222.jpg","https://static.peakview.bg/img/data2/121/hoteli/1222/BIG_3_17593219121222.jpg","https://static.peakview.bg/img/data2/121/hoteli/1222/BIG_4_17593219121222.jpg","https://static.peakview.bg/img/data2/121/hoteli/1222/BIG_5_17593219121222.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е разположен директно на пясъчния плаж в района на Алания – на 22 км от центъра на града, на 35 км от Сиде и на 95 км от международно летище Анталия.</p><p>Плаж</p><p>Хотелът разполага със собствен пясъчен плаж непосредствено пред сградата. Чадъри и шезлонги на плажа и край басейна са безплатни.</p><p><strong>В стаите:</strong>Комплексът предлага общо 221 комфортни стаи, от които 200 стандартни и 21 фамилни. Всички стаи са оборудвани с централен климатик, сателитна телевизия, телефон, баня с душ, сешоар, минибар, сейф (срещу заплащане) и балкон. Почистване се извършва ежедневно, а смяната на бельо и кърпи – три пъти седмично.</p><p><strong>На територията на хотела: </strong>На разположение на гостите са основен ресторант, снек-бар, а-ла-карт ресторант (с предварителна резервация – веднъж седмично), бар, магазини, СПА център, както и открит и закрит басейн. Хотелът предлага също дискотека (срещу заплащане).</p><p>За деца</p><p>Детски басейн, мини клуб (4–12 г.), макси клуб (12–18 г.), площадка за игра, мини диско и специално детско меню в ресторанта.</p><p>Безплатни услуги</p><p>Водна гимнастика, аеробика, дартс, тенис на маса, водна топка, плажен волейбол, баскетбол, турска баня, интернет в лоби бара, анимация и мини клуб.</p><p>Платени услуги</p><p>СПА център, масажи, рум сървиз, интернет кафе, магазини, осветление на тенис кортове, водни спортове, детегледачка.</p><p><strong>Хранене:</strong>Програмата All Inclusive включва закуска, обяд и вечеря на блок маса, междинни закуски и неограничени местни алкохолни и безалкохолни напитки (съгласно концепцията на хотела). </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG_1678117361111.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG_1678117361111.jpg","https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG2_1678117363111.jpg","https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG3_1678117364111.jpg","https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG4_1678117365111.jpg","https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG5_1678117366111.jpg","https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG6_1678117367111.jpg","https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG7_1678117368111.jpg","https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG8_1678117369111.jpg","https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG9_1678117370111.jpg","https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG10_1678117371111.jpg","https://static.peakview.bg/img/data2/121/hoteli/111/BIG_IMG11_1678117371111.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>MIRA MERIDIA BEACH RESORT HOTEL</strong></p><p>Концепция на хотела</p><p><strong>В стаите:</strong>Meridia Beach Hotel е с капацитет от 330 стаи, от които 244 стандартни, 2 свързани стаи, 2 стаи за хора с увреждания, 16 фамилни стаи, 34 Фамилни стаи А изглед градина с две спални и 34 Фамилни стаи В изглед градина с три спални. </p><p>• Стандартни стаи: Има различни видове легла в стандартните стаи.</p><p>Първи вид: 1 спалня и 1 единично легло.</p><p>Втори вид: 1 спалня с 1 разтегателен диван.</p><p>Трети вид: 1 спалня с 1 двуетажно легло</p><p>Размера на стаите е 24 кв.м.</p><p>• Свързани стаи:Този вид се състои от 2 стандартни стаи. Разполага със същите условия, както при стандартните стаи.</p><p>• Стаи за хора с увреждания: Тези стаи са разположени на първия етаж в хотела и са специално проектирани за хората с увреждания, за да имат удобен и лесен достъп до техните спални, бани и тоалетни.</p><p>• Фамилни стаи: Тези стаи са 45 кв.м. и имат 2 спални, 1 баня, с възможност за настаняване до петима възрастни.</p><p>• Клубна Фамилна стая 1: Те се състоят от 2 спални и 1 баня и тоалетна. В основната спалня има 1 двойно легло, а детската стая е с двуетажно легло за двама човека.</p><p>• Клубна фамилна стая 2:Този тип стаи се състои от 3 спални и 1 баня и тоалетна. В основната спалня има едно двойно легло, втората стая има 2 единични легла, а в третата стая има двуетажно легло за двама човека.</p><p><strong>На територията на хотела: </strong>ПЛАЖ: собствен пясъчно - чакълест </p><p>БАСЕЙНИ:1 основен басейн, 1 детски басейн, 1 вътрешен басейн, 1 плувен басейн с 3 пързалки,</p><p>3 басейна разположени във вилната зона ( един от които е с морска вода)</p><p>На Ваше разположение са: Магазин за кожени изделия, Магазин за бижута, Магазин за сувенири, Магазин за дрехи, Rent a car офис, фото студио, мини маркет и фризьорски салон.</p><p>Забавление и анимация:</p><p>• Дневни спортни занимания – водна гимнастика, дартс, тенис на маса, водно поло, аеробика и др.</p><p>• Нощни шоу програми ; скечове , конкурси , жива музика , плажни партита</p><p>• Мини клуб – специални игри, конкурси и мини дискотека за деца в зоните, които са специално създадени за деца</p><p>• Водни спортове – сърф, водно колело, кану, парапланер, водни ски, джет , воден банан</p><p>• Шопинг център – мини маркет, бижутерия, фото студио, магазин за кожени изделия, бутик , магазин за сувенири , аптека , фризьорски салон и други</p><p>• Билярд</p><p>Спа център:</p><p>• Турска баня</p><p>• Масажи</p><p>• Фитнес</p><p>• Сауна</p><p>• Джакузи</p><p>• Вътрешен басейн</p><p>• Салон за красота</p><p>Услуги включени в ALL INCLUSIVE концепцията:</p><p>• Основни хранения, сладолед, gözleme ( турска палачинка ), снек бар, местни и някои вносни алкохолни напитки, както и безалкохолни напитки, всекидневно зареждане на мини бара в стаите, еднократно посещение на À la Carte ресторанта</p><p>• Ползване на басейна и Аквапарка за деца и възрастни</p><p>• Ползване на турска баня, сауна и парна баня</p><p>• Фитнес</p><p>• Участие в анимационните забавления</p><p>• Мини клуб за децата</p><p>• Чадъри, шезлонги, матраци и плажни кърпи</p><p>• Безплатен безжичен интернет в стаите и в лобито на хотела</p><p>• Столчета за хранене за бебета</p><p>• Електронен сейф в стаите</p><p>• Пакети за младоженци, рожденици и годишнини от сватби</p><p>• Паркинг</p><p>Услуги срещу заплащане:</p><p>• Room Service</p><p>• Някои вносни напитки, пакетиран сладолед, фрешове</p><p>• Детегледачка, фотограф, доктор</p><p>• Телефон, факс</p><p>• Мини маркет, rent-a-car-service, фризьор, бижутерия, моторни и немоторни водни спортове</p><p>• Масаж, пилинг, козметични процедури, wellness услуги</p><p>• Химическо чистене и гладене</p><p>• Бебешка количка</p><p>• Водни спортове</p><p>Специални услуги за Младоженци</p><p>• Кошница с плодове и вино в стаята</p><p>• По желание сервиране на закуска в стаята</p><p>• 20 % отстъпка в СПА центъра</p><p>• Специални хотелски услуги</p><p>• По желание – собствена маса с декорация за вечеря</p><p>• Специално спално бельо от сатен</p><p>Специални пакети за рожден ден и годишнина:</p><p>• Кошница с плодове и вино в стаята</p><p>• По желание – собствена маса с декорация в ресторанта</p><p>• Торта (срещу допълнително заплащане) </p><p>Всички тези услуги и работното им време може да се променят в сезона, според метерологичните условия и заетостта на хотела.</p><p><strong>Хранене:</strong>Meridia Beach Hotel се предлага на All Inclusive, който е на Ваше разположение:</p><p>Основни хранения:</p><p>Закуска 07:00 – 10:00 Open Buffet Основен ресторант</p><p>Късна закуска 10:00 – 11:00 Mini Buffet Основен ресторант</p><p>Обяд 12:30 – 14:00 Open Buffet Основен ресторант</p><p>Вечеря 19:00 – 21:00 Open Buffet Основен ресторант</p><p>Късна вечеря 23:30 – 01:00 Mini Buffet Основен ресторант</p><p>През целия престой гостите на хотела имат право на еднократно посещение в A’la Carte ресторанта и се изисква предварителна резервация.</p><p>Барове:</p><p>Lobby-Bar (open 24-hours) 10:00 – 24:00 Всички алкохолни и безалкохолни напитки(24:00-10:00 ч. е срещу допълнително заплащане)</p><p>Pool-Bar 10:00 – 24:00 Всички алкохолни и безалкохолни напитки</p><p>Vitamin-Bar 11:00 – 19:00 Студени и топли безалкохолни напитки</p><p>Beach Bar 10:00 – 17:00 Бира, вино и безалкохолни напитки</p><p>Disco Bar 24:00– 02:00 Всички алкохолни и безалкохолни напитки</p><p>Фрешовете и някои вносни напитки се заплащат допълнително. </p><p>Мини бaрът е зареден еднократно с Кола, Фанта, Минерална вода, натурален сок и те са включени в концепцията за AL Inclusive. Единствено ежедневно се зарежда само минерална вода. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG_158098923214.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG_158098923214.jpg","https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG2_158098923314.jpg","https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG3_158098923414.jpg","https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG4_158098923414.jpg","https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG5_158098923514.jpg","https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG6_158098923514.jpg","https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG7_158098923614.jpg","https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG8_158098923714.jpg","https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG9_158098923714.jpg","https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG10_158098923814.jpg","https://static.peakview.bg/img/data2/121/hoteli/14/BIG_IMG11_158098923914.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира на 26 км от центъра на Алания, на 104 км от летище Анталия, 114км от центъра на Анталия.</p><p><strong>В стаите:</strong>Хотелът разполага с 3 сгради, със 174 стаи за гости. Всички стаи са оборудвани с централна климатична система, сейф, телевизор със сателитни канали, телефон с директно набиране, мини бар, балкон, баня с душ или вана и тоалетна, сешоар.</p><p><strong>На територията на хотела: </strong>На територията на хотела:</p><p>Основен ресторант с вътрешна и външна част, а-ла-карт ресторант, бар при басейна , бар на плажа, лоби бар, диско бар, 2 басейна, пързалка, детски басейн, амфитеатър, дневно и нощно шоу, мини клуб, фитнес, водни спортове, плажен волейбол, дартс, аеробика, тенис на корт, тенис на маса, сауна, турска баня, СПА и уелнес център.</p><p>Плаж:</p><p>Собствен плаж, шезлонги и чадъри на плажа и басейна - безплатно.</p><p><strong>Хранене:</strong>ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG_1580999918101.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG_1580999918101.jpg","https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG2_1580999919101.jpg","https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG3_1580999919101.jpg","https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG4_1580999920101.jpg","https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG5_1580999921101.jpg","https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG6_1580999921101.jpg","https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG7_1580999922101.jpg","https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG8_1580999922101.jpg","https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG9_1580999923101.jpg","https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG10_1580999924101.jpg","https://static.peakview.bg/img/data2/121/hoteli/101/BIG_IMG11_1580999924101.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е отворен от 1990г. и последно реновиран през 2016г. Намира се на 110 км. от Анталия, 98 км. от летището на гр. Анталия, около 35 км. от Манавгат и Сиде, на 20 км. от Алания, на брега на морето.</p><p>Обща площ 110 хил. м².</p><p><strong>В стаите:</strong>Стаи:</p><p>Всички стаи са оборудвани с индивидуален климатик, сателитна телевизия, телефон с директно избиране, баня с душ или вана, сешоар, минибар, сейф, керамично или ламинирано подово покритие, балкон. Ежедневно почистване на стаите. Смяна на спалното бельо и на кърпите - 3 пъти в седмицата.</p><p><strong>На територията на хотела: </strong>Удобства:</p><p>Два основни ресторанта, два а-ла-карт ресторанта, гьозлеме пекарна, барове и снек барове, дискотека, седем открити басейна, два закрити басейна, седем детски басейна, два аквапарка, SPA център, фитнес зала, телевизионна зала, киносалон, анимационна програма, вечерни представления, развлекателни и спортни дейности, конферентни зали, собствен паркинг.</p><p>Безплатни Услуги:</p><p>Турска баня, парна баня и сауна, фитнес зала, всички дейности от анимационната програма, чадъри и шезлонги на плажа и при басейните.</p><p>Платени Услуги:</p><p>Масажи и други козметични процедури, фризьорски услуги, магазини, зала за игри, билярд и футбол на маса, пералня, лекар, резервация за а-ла-карт ресторант, вход за дискотеката, осветление за тенис кортовете, водни спортове.</p><p>Плаж:</p><p>Собствена пясъчна плажна ивица. Безплатно ползване на чадъри и шезлонги на плажа и при басейните.</p><p><strong>Хранене:</strong>ULTRA ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/31/BIG_eftalia-marin-5-0-900x500_158100340531.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/31/BIG_eftalia-marin-5-0-900x500_158100340531.jpg","https://static.peakview.bg/img/data2/121/hoteli/31/BIG_eftalia-marin-5-2-900x500_158100340531.jpg","https://static.peakview.bg/img/data2/121/hoteli/31/BIG_eftalia-marin-5-3-900x500_158100340531.jpg","https://static.peakview.bg/img/data2/121/hoteli/31/BIG_eftalia-marin-5-4-900x500_158100340531.jpg","https://static.peakview.bg/img/data2/121/hoteli/31/BIG_eftalia-marin-5-5-900x500_158100340531.jpg","https://static.peakview.bg/img/data2/121/hoteli/31/BIG_eftalia-marin-5-6-900x500_158100340531.jpg","https://static.peakview.bg/img/data2/121/hoteli/31/BIG_eftalia-marin-5-7-900x500_158100340531.jpg","https://static.peakview.bg/img/data2/121/hoteli/31/BIG_eftalia-marin-5-8-900x500_158100340531.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира на 110 км. от центъра на Анталия, на 100 км. от летище Анталия, на 18км. от гр.Алания, в района на Алания, на 50 м. от брега на морето. Построен през 2014 г.</p><p><strong>В стаите:</strong>Хотелът разполага общо с 491 стаи, от които 237 стандартни стаи и 249 фамилни стаи. Всички стаи са оборудвани с климатик, сателитна телевизия, телефон, баня с душ, сешоар, мини бар (платен), сейф (безплатен), балкон. Почистване на стаите – всеки ден.</p><p><strong>На територията на хотела: </strong>Основен ресторант, а - ла - карт ресторант (с предварителна резервация), 10 бара, сладкарница, 8 басейна, вътрешен басейн, водни пързалки, аквапарк – Eftalia Island, магазини, SPA център, конферентна зала.</p><p>За децата: Детска площадка, мини клуб (4-12 г.), детски басейн, водни пързалки.</p><p>Безплатни услуги: Сауна, фитнес, дартс, тенис на маса, плажен волейбол, аеробика, анимация, интернет, паркинг.</p><p>Платени услуги: Масаж, фризьор, магазини, химическо чистене, лекар, водни спортове, дискотека.</p><p>ПЛАЖ: На 50 м. през път, собствен, пясъчно - чакълест. Чадъри, шезлонги и матраци на плажа и при басейна – безплатно, плажни кърпи – безплатно.</p><p><strong>Хранене:</strong>Ultra All Inclusive – закуска, обяд, вечеря и междинни хранения на шведска маса, местни алкохолни и безалкохолни напитки - без лимит. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/32/BIG_eftalia-ocean-1a_158106446332.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/32/BIG_eftalia-ocean-1a_158106446332.jpg","https://static.peakview.bg/img/data2/121/hoteli/32/BIG_ed2046ec-z_158106446332.jpg","https://static.peakview.bg/img/data2/121/hoteli/32/BIG_eftalia-ocean-1_158106446332.jpg","https://static.peakview.bg/img/data2/121/hoteli/32/BIG_eftalia-ocean-2_158106446332.jpg","https://static.peakview.bg/img/data2/121/hoteli/32/BIG_eftalia-ocean-2a_158106446332.jpg","https://static.peakview.bg/img/data2/121/hoteli/32/BIG_eftalia-ocean-2b_158106446332.jpg","https://static.peakview.bg/img/data2/121/hoteli/32/BIG_eftalia-ocean-3_158106446332.jpg","https://static.peakview.bg/img/data2/121/hoteli/32/BIG_eftalia-ocean-4_158106446332.jpg","https://static.peakview.bg/img/data2/121/hoteli/32/BIG_eftalia-ocean-5_158106446332.jpg","https://static.peakview.bg/img/data2/121/hoteli/32/BIG_eftalia-ocean-7_158106446332.jpg","https://static.peakview.bg/img/data2/121/hoteli/32/BIG_eftalia-ocean-8_158106446332.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира на 110 км. от центъра на Анталия, на 100 км. от летище Анталия, нa 4 км. от Конаклъ, на 18 км. от гр.Алания, в района на Алания, на брега на морето. Построен през 2017 г. на площ от 60000m2.</p><p><strong>В стаите:</strong>Хотелът разполага с 682 стаи. Всички стаи са оборудвани с климатик, сателитна телевизия, телефон, баня с душ, сешоар, мини бар (платен), сейф (безплатен), балкон. Почистване на стаите – всеки ден.</p><p><strong>На територията на хотела: </strong>Основен ресторант, а - ла - карт ресторант (италиански и грил, с предварителна резервация), 8 бара, сладкарница, 8 басейна, аквапарк – Eftalia Island и собствен аквапарк със 7 пързалки, магазини, SPA център, паркинг.</p><p>За децата: Детска площадка, мини клуб (4-12 г.), детски басейн, 5 водни пързалки.</p><p>Безплатни услуги: Сауна, фитнес, дартс, тенис на маса, плажен волейбол, аеробика, анимация, интернет, паркинг.</p><p>Платени услуги: Масаж, фризьор, магазини, химическо чистене, лекар, водни спортове, дискотека.</p><p>ПЛАЖ: Собствен, пясъчно - чакълест. Чадъри, шезлонги и матраци на плажа и при басейна – безплатно, плажни кърпи – безплатно.</p><p><strong>Хранене:</strong>Ultra All Inclusive – закуска, обяд, вечеря и междинни хранения на шведска маса, местни алкохолни и безалкохолни напитки - без лимит. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e1_17525661261124.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e1_17525661261124.jpg","https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e3_17525661261124.jpg","https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e4_17525661261124.jpg","https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e5_17525661261124.jpg","https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e6_17525661261124.jpg","https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e7_17525661261124.jpg","https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e8_17525661261124.jpg","https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e9_17525661261124.jpg","https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e10_17525661261124.jpg","https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e11_17525661261124.jpg","https://static.peakview.bg/img/data2/121/hoteli/1124/BIG_e12_17525661261124.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотел Eftalia Blue се намира в туристическия район Тюрклер, на около 18 км от центъра на Алания и на около 100 км от летище Анталия. Разположен е в близост до плажа, част от комплекса Eftalia Island, с достъп до голяма аква зона и множество удобства за семейства.</p><p><strong>В стаите:</strong>Стандартни и фамилни стаи, модерно обзаведени. Всички помещения са климатизирани и разполагат с балкон, телевизор, минибар, сейф (платен), баня с душ.</p><p><strong>На територията на хотела: </strong>Модерен 5-звезден хотел, част от Eftalia Hotels. Разполага с няколко открити басейна, водни пързалки, спа център, ресторанти, барове и достъп до голям плажен клуб. Хотелът е особено подходящ за семейства с деца, благодарение на анимацията и детските зони.</p><p><strong>Хранене:</strong>Ултра Ол Инклузив (Ultra All Inclusive) – богата закуска, обяд, вечеря на блок маса, междинни закуски, сладолед, местни и някои вносни напитки почти денонощно. Специални тематични вечери и снек барове на територията на комплекса. </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG_1678177658691.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG_1678177658691.jpg","https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG2_1678177659691.jpg","https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG3_1678177660691.jpg","https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG4_1678177661691.jpg","https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG5_1678177661691.jpg","https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG6_1678177662691.jpg","https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG7_1678177663691.jpg","https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG8_1678177663691.jpg","https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG9_1678177664691.jpg","https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG10_1678177665691.jpg","https://static.peakview.bg/img/data2/121/hoteli/691/BIG_IMG11_1678177665691.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>OZ HOTELS SUI</strong></p><p>Sui Resort Hotel е разположен в района на Okurcalar, само на 400 метра от морето, и разполага с открит басейн, спа център, собствен плаж и безплатен WiFi.</p><p>Всяка стая в хотела е климатизирана и разполага с телевизор с плосък екран и собствена баня с безплатни тоалетни принадлежности и сешоар. Някои стаи са с изглед към морето или басейна.</p><p>Можете да се храните в ресторанта и да си поръчате напитки в бара. Възможностите за хранене включват а ла карт ресторант и ресторант на шведска маса.</p><p>Хотелът разполага с условия за водни спортове и предлага автомобили под наем. На разположение са и маси за тенис и билярд.</p><p>Летище &bdquo;Gazipasa&ldquo; се намира на 68 километра, а на място им безплатен собствен паркинг.</p><p>Концепция на хотела</p><p><strong>Хранене:</strong>ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG_1609329012636.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG_1609329012636.jpg","https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG2_1609329014636.jpg","https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG3_1609329014636.jpg","https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG4_1609329015636.jpg","https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG5_1609329016636.jpg","https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG6_1609329017636.jpg","https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG7_1609329017636.jpg","https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG8_1609329018636.jpg","https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG9_1609329019636.jpg","https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG10_1609329020636.jpg","https://static.peakview.bg/img/data2/121/hoteli/636/BIG_IMG11_1609329020636.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е разположен на 125 км от летището в град Анталия, на 7 км от град Алания, на 5 км от селището Конаклъ, на 100 м през пътя от плажа.</p><p>Построен е през 1991 год.</p><p><strong>В стаите:</strong>В стаите:</p><p>вана или душ, сешоар, индивидуален климатик, телевизор, телефон, мини-бар (вода, безалкохолни напитки - зареждат се ежедневно, безплатно), сейф (срещу депозит), балкон, room service (24 часа, платено).</p><p><strong>На територията на хотела: </strong>Хотелът разполага с:</p><p>основен ресторант, диетично меню, 3 а ла карте ресторанта (италиански, османски, рибен - с предварителна резервация), 6 бара, 2 открити басейна, закрит басейн, 3 водни пързалки, лекарски кабинет, фризьорски салон (платено), търговска алея, пералня, 4 конферентни зали (за 35-500 души).</p><p>Плаж:</p><p>Собствен плаж с пясък/чакъл.</p><p>Кей.</p><p>Бар на плажа: безплатно.</p><p>На плажа и при басейна: чадъри, шезлонги, матраци – безплатно.</p><p>Плажни кърпи: платено.</p><p><strong>Хранене:</strong>ULTRA ALL INCLUSIVE - за летния сезон </p><p>* зимна концепция - ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG_158098943517.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG_158098943517.jpg","https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG2_158098943617.jpg","https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG3_158098943717.jpg","https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG4_158098943717.jpg","https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG5_158098943817.jpg","https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG6_158098943817.jpg","https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG7_158098943917.jpg","https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG8_158098943917.jpg","https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG9_158098944017.jpg","https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG10_158098944017.jpg","https://static.peakview.bg/img/data2/121/hoteli/17/BIG_IMG11_158098944117.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Aska Just In Beach се намира на по-малко от 50 м от плажа. На 25 км от Алания и на 40 км от Манавгат.</p><p><strong>В стаите:</strong>Стаите разполагат с климатик, сейф, мини бар, телевизор и други.</p><p><strong>На територията на хотела: </strong>Хотелът предоставя безплатен Wi-Fi достъп до интернет в общите части. Разполага със закрит и открит плувен басейн, фитнес зала, масаж, сауна, турска баня. Има също тенис корт на място, както и зала за игри с маси за тенис и билярд. Сред заниманията, предлагани на плажа са гмуркане, парасейлинг и джет ски.</p><p>Също така:</p><p>Ресторант, Бар, Сейф, Денонощна рецепция, Помещение за съхранение на багаж, Пералня, Химическо чистене, Гладене.</p><p><strong>Хранене:</strong>ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG_167817823910.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG_167817823910.jpg","https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG2_167817824010.jpg","https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG3_167817824110.jpg","https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG4_167817824210.jpg","https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG5_167817824310.jpg","https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG6_167817824310.jpg","https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG7_167817824410.jpg","https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG8_167817824510.jpg","https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG9_167817824510.jpg","https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG10_167817824610.jpg","https://static.peakview.bg/img/data2/121/hoteli/10/BIG_IMG11_167817824710.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е разположен на 100 км от летището в Анталия, на 22 км от гр. Алания, в селището Турклер, на брега на морето.</p><p><strong>В стаите:</strong>Стаи:</p><p>душ, сешоар, балкон, телефон, телевизор, сейф: в стаята, платено, индивидуален климатик, мини бар безплатно (безалкохолни напитки в деня на настаняване), подово покритие: керамични плочки, почистване на стаята: ежедневно, смяна на спалното бельо: 3 пъти седмично.</p><p><strong>На територията на хотела: </strong>Състои се от 20 триетажни корпуса: 384 standard room (от тях 4 номера за инвалиди, макс. 2+2 чов., 27 м2).</p><p>Удобства:</p><p>1 основен ресторант, 4 бара, 2 открити басейна, 2 водни пързалки, интернет Wi-Fi - платено (на територията на хотела), магазини</p><p>Безплатни Услуги:</p><p>аеробика, фитнес зала, плажен волейбол, дартс, тенис на маса, баскетбол, анимация, тенис корт (с твърдо покритие)</p><p>Платени Услуги:</p><p>масаж, сауна, турска баня (хамам), осветление на тенис корта, билярд, водни спортове</p><p>Плаж:</p><p>Собствен пясъчен плаж. На басейна и на плажа: чадъри, шезлонги: безплатно; матраци и плажни хавлии: платено.</p><p><strong>Хранене:</strong>ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_FLKD3T7A_17654418881380.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_FLKD3T7A_17654418881380.jpg","https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_2UCX4EWB_17654418881380.jpg","https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_2VAXYFHK_17654418881380.jpg","https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_A5BEWJPV_17654418881380.jpg","https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_EQ5ZXV4Y_17654418881380.jpg","https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_F4RM2ZVH_17654418881380.jpg","https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_BIG_TIMO%20RESORT26_16552179683229_17654418881380.jpg","https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_JFUMY76K_17654418881380.jpg","https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_BIG_TIMO%20RESORT19_16552179683229_17654418881380.jpg","https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_Y6W4Z8JR_17654418881380.jpg","https://static.peakview.bg/img/data2/121/hoteli/1380/BIG_BIG_TIMO%20RESORT16_16552179683229_17654418881380.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира на разстояние от 110 км. от летището в Анталия, разположен в Конаклъ, на 15км. от Алания.</p><p><strong>В стаите:</strong>Стаите:</p><p>Всички стаи в хотела разполагат с централна климатизация, мини-бар, сателитна телевизия, телефон, баня с вана и/или душ, сешоар, балкон/тераса, сейф.</p><p>Standard Room – 30кв.м., максимално настаняване – 3-ма възрастни + 1 дете. 1 спалня – 1 двойно легло, 1 единично легло + разтегателен диван.</p><p>Family Room – 36кв.м., максимално настаняване – 4-ма възрастни + 1 дете. 2 спални с 1 двойно легло, 2 допълнителни легла + разтегателен диван.</p><p>Suite Room – 55кв.м., максимално настаняване – 4-ма възрастни + 2 деца. . 2 спални с 1 двойно легло, 2 единични легла + разтегателен двоен диван.</p><p><strong>На територията на хотела: </strong>Timo Deluxe Resort 5* е с площ от 13 067 кв.м. Състои се от една 6-етажна сграда. Разполага със собствен пясъчен плаж – на разстояние 75м. от територията на хотела. Предлага 3 басейна, малък аквапарк с 3 пързалки, безплатен паркинг, безплатен wi-fi на територията на хотела, фитнес център и всичко необходимо за една пълноценна ваканция.</p><p><strong>Хранене:</strong>ALL INCLUSIVE-закуска, обяд и вечеря на шведска маса, допълнителни хранения, местни напитки без лимит </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363995-POOL-2_1608195728602.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363995-POOL-2_1608195728602.jpg","https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363989-NIGHT-VIEW-2_1608195728602.jpg","https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363981-GENERAL-VIEW-2_1608195728602.jpg","https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363981-genel-1_1608195728602.jpg","https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363980-gece-goruntu-4_1608195728602.jpg","https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363980-gece-goruntu-3_1608195728602.jpg","https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363976-BEACH_1608195728602.jpg","https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363954-AQUAPARK_1608195728602.jpg","https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363974-ATRIUM1_1608195728602.jpg","https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363978-DA-VINCI-ALA-CARTE-1_1608195728602.jpg","https://static.peakview.bg/img/data2/121/hoteli/602/BIG_1516363985-LOBBY-4_1608195728602.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е разположен на 100 км от летището в гр. Анталия, на 15 км от гр. Алания, на 350 м от през пътя чрез подлез от собствения си плаж.</p><p><strong>В стаите:</strong>Стаи:</p><p>душ, сешоар, централен климатик, телевизор, телефон, мини-бар (вода и минерална вода се зарежда ежедневно, безплатно), сейф (безплатно), балкон, подова настилка - паркет, безжичен интернет (безплатно), почистване на стаята - ежедневно, смяна на спалното бельо - 3 пъти седмично, room service (24 часа)</p><p><strong>На територията на хотела: </strong>В хотела:</p><p>Състои се от една 9-етажна основна сграда Maing Building и осемнадесет 3-етажни вили.</p><p>Maing Building:</p><p>581 superior standard room (от тях 8 стаи за инвалиди, макс. 3+1 чов., 37-46 м2)</p><p>192 двустайни family room -family suite pool view/ land view (2 спални с врата, макс. 4+1 чов., 50 м2)</p><p>Villa:</p><p>18 двустайни Vip villa-family villa with pool (хол, спалня с врата, макс. 4+1 чов., 50 м2) </p><p>Удобства:</p><p>основен ресторант, 3 ресторанта a-la-carte (италиански, турски, далекоизточен, с предварителна резервация, за едноседмичен престой посещение на един от ресторантите - безплатно), 5 бара, 2 открити басейна, закрит басейн, 10 водни пързалки, лекарски кабинет, SPA-център, фризьорски салон, търговска част, пералня, химическо чистене, конферентна зала (за 1200 чов.), безжичен интернет (на цялата територия на хотела, безплатно)</p><p>Безплатни Услуги:</p><p>турска баня, сауна, парна баня, джакузи, фитнес, аеробика, аквааеробика, плажен волейбол, тенис на корт със синтетично покритие, наем на тенис ракети и топки, тенис на маса, дартс, боча, стрелба с лък и пневматично оръжие, анимационна програма, музика на живо (1 път седмично), дискотека</p><p>Платени Услуги:</p><p>масаж, боулинг (2 пътеки), билярд, игрални автомати, осветление на тенис кортовете, водни спортове, интернет-кафе</p><p>Плаж:</p><p>Собствен, пясък и чакъл. Бар на плажа: безплатно. На басейна и на плажа: чадъри, шезлонги, матраци - безплатно. Плажни кърпи - безплатно; замяна - платено. Трансфер до плажа: на всеки 15 мин. (безплатно).</p><p><strong>Хранене:</strong>ULTRA ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG_1610550944659.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG_1610550944659.jpg","https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG2_1610550946659.jpg","https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG3_1610550946659.jpg","https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG4_1610550947659.jpg","https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG5_1610550948659.jpg","https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG6_1610550948659.jpg","https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG7_1610550949659.jpg","https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG8_1610550950659.jpg","https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG9_1610550951659.jpg","https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG10_1610550951659.jpg","https://static.peakview.bg/img/data2/121/hoteli/659/BIG_IMG11_1610550952659.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира в Инджекум, на 33 км. от центъра на Алания и на 95 км. от летище Анталия.</p><p>Официално е открит през 2004 г. върху площ от 70 000 кв.м. Последна реновация 2016 година.</p><p><strong>В стаите:</strong>Хотелът се състои от 12 триетажни корпуса и разполага с 354 стаи. Всички стаи са оборудвани с: климатик, баня с душ, сешоар, телевизор, телефон, мини - бар (безплатно), сейф (безплатно).</p><p><strong>На територията на хотела: </strong>Хотелът разполага с:</p><p>• Основен ресторант</p><p>• 1 a - лa - карт ресторант</p><p>• 3 бара</p><p>• 3 пързалки</p><p>• Открит басейн, закрит басейн, детски басейн</p><p>• Магазини</p><p>За децата:</p><p>Детско меню, детски басейн, детска площадка, мини – клуб</p><p>Безплатни услуги:</p><p>Дискотека, турска баня, аеробика, волейбол, баскетбол, тенис на маса, тенис на корт, мини – футбол, безжичен интернет – на лоби и басейн.</p><p>Платени услуги:</p><p>Доктор, масаж, бавачка , билярд, СПА - център, осветление на тенис кортовете</p><p>Плаж:</p><p>Пясъчно – чакълест и 2 пирса на 300 метра от хотела. Чадъри и шезлонги на плажа и при басейна - безплатно. Плажни кърпи - срещу депозит. Бар на плажа – безплатно.</p><p><strong>Хранене:</strong>ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG_1638527045806.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG_1638527045806.jpg","https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG2_1638527047806.jpg","https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG3_1638527048806.jpg","https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG4_1638527049806.jpg","https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG5_1638527051806.jpg","https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG6_1638527052806.jpg","https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG7_1638527052806.jpg","https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG8_1638527053806.jpg","https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG9_1638527054806.jpg","https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG10_1638527055806.jpg","https://static.peakview.bg/img/data2/121/hoteli/806/BIG_IMG11_1638527056806.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>KAILA BEACH HOTEL</strong></p><p>KAILA BEACH HOTEL All Inclusive се намира на Турската Ривиера, на 1,5 км от Алания. Той е заобиколен от тропическа градина и предлага открит басейн с водна пързалка и безплатен WiFi.</p><p>Просторните и съвременни стаи в KAILA BEACH HOTEL са разположени до плажа на Алания. Всяка включва климатик, сателитна телевизия, кът за сядане и балкон. За гостите са осигурени безплатни тоалетни принадлежности през целия престой.</p><p>В KAILA BEACH HOTEL има няколко заведения за хранене и освежаващи напитки, сред които бар край басейна, ресторант с ястия на шведска маса и а ла карт ресторантите Kaktus и Ottoman. Ястията могат да се сервират и в стаите на гостите.</p><p>Луксозните съоръжения в хотела се допълват от закрит басейн, игрище за плажен волейбол, парна баня и сауна. Гостите могат да тренират в добре оборудвания фитнес център. Децата могат да се забавляват в мини клуба или на детската площадка.</p><p>Персоналът в KAILA BEACH HOTEL може да предостави информация за забележителностите и дейностите в района. Рецепцията е отворена денонощно и при заявка служителите организират трансфер с автобус до местните нощни заведения.</p><p>Концепция на хотела</p><p><strong>Хранене:</strong>ALL INCLUSIVE </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/873/BIG_1-Hotel-17-1_1675847137873.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/873/BIG_1-Hotel-17-1_1675847137873.jpg","https://static.peakview.bg/img/data2/121/hoteli/873/BIG_1-Hotel-16_1675847137873.jpg","https://static.peakview.bg/img/data2/121/hoteli/873/BIG_1-Hotel-13_1675847137873.jpg","https://static.peakview.bg/img/data2/121/hoteli/873/BIG_1-Hotel-12-1_1675847137873.jpg","https://static.peakview.bg/img/data2/121/hoteli/873/BIG_1-Hotel-10_1675847137873.jpg","https://static.peakview.bg/img/data2/121/hoteli/873/BIG_1-Hotel-27_1675847137873.jpg","https://static.peakview.bg/img/data2/121/hoteli/873/BIG_6-Beach-4_1675847137873.jpg","https://static.peakview.bg/img/data2/121/hoteli/873/BIG_5-Swimming-Pool-9_1675847137873.jpg","https://static.peakview.bg/img/data2/121/hoteli/873/BIG_6-Beach-6_1675847137873.jpg","https://static.peakview.bg/img/data2/121/hoteli/873/BIG_6-Beach-7_1675847137873.jpg","https://static.peakview.bg/img/data2/121/hoteli/873/BIG_9-Pool-Bar-1_1675847137873.jpg"],stars:4,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът се намира в курорта Конаклъ, на 110 километра от международното летище на Анталия, на 12 километра от градската част на Алания, на брега на морето с площ от 10 000 m².</p><p><strong>В стаите:</strong>Хотелът се състои от една основна шестетажна сграда и разполага с общо 301 стаи, 60 от които предлагат частичен или директен изглед към морето.</p><p>Всички стаи са оборудвани с индивидуален климатик, LCD телевизор със сателитен приемник, телефон с директно избиране, баня с душ, сешоар, минибар (ежедневно презареждан с вода), сейф (срещу 2 евро на ден), безжичен интернет срещу заплащане (10 евро за целия престой), балкон.</p><p>Ежедневно почистване на стаите, смяна на спалното бельо и хавлиите – 2 пъти в седмицата.</p><p><strong>На територията на хотела: </strong>Основен ресторант, 4 бара, гьозлеме на плажа, открит басейн, водни пързалки, SPA център със закрит басейн, турска баня и сауна, фитнес зала, анимационна програма, дартс, тенис на маса, аеробика, водна гимнастика, плажен волейбол, водна топка, амфитеатър за вечерни представления, дискотека на открито, търговски център, безжичен интернет Wi-fi - само срещу допълнително заплащане,</p><p>За децата: детска площадка, мини клуб с детски аниматори, мини дискотека, детски басейн и детска водна пързалка.</p><p>Платени услуги: масажи, сауна, фризьорски и козметични услуги, медицински услуги, водни спортове, наем на лек автомобил, пералня, билярд, безжичен интернет на територията на целия хотел, вход за дискотеката, плажни кърпи.</p><p>Плаж:</p><p>Собствена пясъчно-чакълеста плажна ивица с дължина 130 метра и широчина 35 метра.</p><p>Общ плаж с хотел CARETTA RELAX HOTEL</p><p>Безплатно ползване на чадъри, шезлонги и матраци на плажа и при басейна, плажни кърпи – срещу допълнително заплащане.</p><p><strong>Хранене:</strong>All Inclusive </p>"};
HOTEL_INFO["https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG_167818108597.jpg"]={images:["https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG_167818108597.jpg","https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG2_167818108697.jpg","https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG3_167818108797.jpg","https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG4_167818108797.jpg","https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG5_167818108897.jpg","https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG6_167818108897.jpg","https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG7_167818108997.jpg","https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG8_167818109097.jpg","https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG9_167818109097.jpg","https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG10_167818109197.jpg","https://static.peakview.bg/img/data2/121/hoteli/97/BIG_IMG11_167818109297.jpg"],stars:5,location:"Анталия, Алания , Турция",desc:"<p><strong>Разположение:</strong>Хотелът е разположен на живописния залив Фугла в курортния район Тюрклер, на 98 км. източно от международното летище на Анталия, на 26 км. западно от централната част на гр. Алания и на 240 м. от брега на морето.</p><p><strong>В стаите:</strong>Стандартните двойни стаи са с площ от 36 кв.м. и са с капацитет за трима възрастни или за двама възрастни с две деца. Оборудвани са с двойно легло, единично легло и диван.</p><p>Супериорните стаи са с площ от 72 м² и са с капацитет за трима възрастни. Разполагат с джакузи на балкона.</p><p>Фамилните стаи се състоят от две отделни свързани спални помещения и са с максимален капацитет за петима възрастни с бебе.</p><p>Всички стандартни, супериорни и фамилни стаи са оборудвани с индивидуален климатик, сателитна телевизия, телефон, баня с душ или вана, сешоар, минибар, сейф, електрическа кана, продукти за приготвяне на чай и кафе, ламинирано подово покритие и балкон.</p><p>Ежедневно почистване на стаите. Смяна на спалното бельо – 3 пъти в седмицата. Смяна на кърпите в банята - по желание на гостите.</p><p><strong>На територията на хотела: </strong>Хотелът представлява масивна модерна шестетажна сграда, разполагаща с общо 821 стаи и леглова база от 1800 легла. </p><p>Удобства:</p><p>Основен ресторант, два а-ла-карт ресторанта, сладкарница, гьозлеме пекарна, лоби бар, барове и снек бар при басейните, бирария в градината, дискотека, два открити басейна, закрит басейн, два детски басейна, детски водни пързалки, SPA център, фитнес зала, козметичен салон, библиотека, телевизионна зала, зала за игри, търговски обекти, развлекателни и спортни дейности, целодневна анимационна програма, вечерни представления, конферентни зали, безжичен интернет, собствен паркинг.</p><p>Безплатни Услуги:</p><p>Турска баня, парна баня и сауна, фитнес, всички дейности от анимационната програма, чадъри и шезлонги на плажа и при басейните, безжичен интернет в лоби.</p><p>Платени Услуги:</p><p>Масажи и други козметични процедури, фризьорски услуги, магазини, зала за игри, батут, билярд и футбол на маса, пералня, лекар, осветление на тенис корта, резервация за посещение на а-ла-карт ресторант, вход за дискотеката, ползване на сейф в стаята, всички водни спортове.</p><p>Плаж:</p><p>Две собствени пясъчни плажни ивици, отдалечени на приблизително 240 м. от сградата на хотела. Безплатно ползване на чадъри, шезлонги и матраци на плажа и при басейните.</p><p><strong>Хранене:</strong>Ultra All Inclusive </p>"};
